const LIBRARY = [
  // ── STOCKS ─────────────────────────────────────────────────────────────────
  {
    id: 'stocks', icon: '📈', title: 'Stocks',
    desc: 'Stock market basics, PSX, global exchanges, IPOs, dividends, and investing concepts.',
    topics: [
      { id: 'what-is-stock-market', title: 'What is the Stock Market?', level: 'Beginner', summary: 'An introduction to stock markets, how they work, and why they exist.',
        content: [
          { type: 'image', src: 'images/SNRST001.jpg', alt: 'What is the Stock Market' },
          { type: 'paragraph', text: 'The stock market is a regulated financial marketplace where shares of publicly listed companies are bought and sold. It connects companies seeking capital with investors who are willing to provide funds in exchange for ownership participation, potential capital appreciation, dividends, or long-term wealth creation.' },
          { type: 'paragraph', text: 'When a company becomes publicly listed, its shares can be traded by investors through a stock exchange or regulated trading platform. These shares represent ownership interest in the company. As the company grows, earns profits, expands operations, or improves its market position, the value of its shares may increase. However, if business performance weakens or market conditions deteriorate, share prices may decline.' },
          { type: 'heading', text: 'Role in the Economy' },
          { type: 'paragraph', text: 'The stock market plays a critical role in the economy. It helps companies raise capital for expansion, supports business growth, provides liquidity to investors, and reflects market expectations about corporate performance and economic conditions. Stock prices are influenced by many factors, including earnings, interest rates, inflation, economic growth, investor sentiment, sector performance, government policy, and global events.' },
          { type: 'heading', text: 'Opportunities and Risks' },
          { type: 'paragraph', text: 'For investors, the stock market offers opportunities for wealth creation through capital gains and dividends. For traders, it provides opportunities to benefit from shorter-term price movements. However, the stock market also involves risk, and price movement can be unpredictable in the short term. A professional understanding requires knowledge of company fundamentals, market structure, valuation, technical analysis, risk management, and investor psychology.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> The stock market is a regulated capital market where ownership interests in listed companies are traded, enabling capital formation, price discovery, liquidity, and investor participation in corporate growth.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, hold, or trade any stock or financial instrument. Stock market investing and trading involve risk, including possible loss of capital. Conduct your own research and consult qualified professionals before making any financial decision.' },
        ]
      },
      { id: 'how-stock-exchanges-work', title: 'How Stock Exchanges Work', level: 'Beginner', summary: 'Understanding the mechanics of stock exchanges and trading platforms.',
        content: [
          { type: 'image', src: 'images/SNRST002.jpg', alt: 'How Stock Exchanges Work' },
          { type: 'paragraph', text: 'A stock exchange is an organized and regulated marketplace where securities such as shares, exchange-traded funds, bonds, and other financial instruments are listed and traded. It provides the infrastructure required for buyers and sellers to meet through a transparent and rule-based trading system.' },
          { type: 'heading', text: 'Order Matching and Price Discovery' },
          { type: 'paragraph', text: 'Stock exchanges do not usually buy or sell shares directly for investors. Instead, they provide the platform where orders are matched through brokers, trading systems, and clearing mechanisms. Share prices continuously adjust based on supply and demand. When more buyers are willing to purchase a stock at higher prices, the price may rise. When more sellers are willing to sell at lower prices, the price may fall.' },
          { type: 'heading', text: 'Liquidity and Regulation' },
          { type: 'paragraph', text: 'Stock exchanges support liquidity, meaning investors can buy or sell shares more easily without causing major price disruption. Exchanges also operate under rules designed to promote transparency, fair trading, timely disclosure, and investor protection. Listed companies are generally required to publish financial statements, disclose material information, and follow governance standards.' },
          { type: 'heading', text: 'Clearing and Settlement' },
          { type: 'paragraph', text: 'Behind every trade, there are clearing and settlement processes. These ensure that shares are transferred to the buyer and funds are transferred to the seller according to market rules.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> A stock exchange is a regulated trading infrastructure that enables listing, order matching, price discovery, liquidity, clearing, settlement, and transparent participation in capital markets.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to use any exchange, broker, or trade any financial instrument. Trading on an exchange does not eliminate market risk or capital loss. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'primary-vs-secondary', title: 'Primary vs Secondary Market', level: 'Beginner', summary: 'The difference between where stocks are first issued and where they are traded.',
        content: [
          { type: 'image', src: 'images/SNRST003.jpg', alt: 'Primary vs Secondary Market' },
          { type: 'paragraph', text: 'The stock market is commonly divided into two major segments: the primary market and the secondary market. Understanding the difference between them is essential for anyone learning how capital markets function.' },
          { type: 'heading', text: 'Primary Market' },
          { type: 'paragraph', text: 'The primary market is where securities are issued for the first time. When a company raises capital by offering shares to investors through an Initial Public Offering, rights issue, or private placement, the transaction takes place in the primary market. In this market, the company receives the money raised from investors.' },
          { type: 'heading', text: 'Secondary Market' },
          { type: 'paragraph', text: 'The secondary market is where already-issued securities are bought and sold among investors. After a company\'s shares are listed on a stock exchange, investors can trade those shares with one another. In the secondary market, the company usually does not receive money from daily trading activity. Instead, investors exchange ownership with each other.' },
          { type: 'heading', text: 'Why Both Markets Matter' },
          { type: 'paragraph', text: 'The primary market supports capital formation, helping businesses raise funds for expansion. The secondary market supports liquidity and price discovery, allowing investors to enter or exit positions. Both markets are connected — a strong secondary market gives investors confidence to participate in primary offerings.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> The primary market enables companies to raise fresh capital by issuing securities, while the secondary market provides liquidity and price discovery for securities already issued.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to participate in any IPO, offering, or trade any financial instrument. Primary and secondary market participation involves risk. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'what-is-ipo', title: 'What is an IPO?', level: 'Beginner', summary: 'How companies go public and what an IPO means for investors.',
        content: [
          { type: 'image', src: 'images/SNRST004.jpg', alt: 'What is an IPO' },
          { type: 'paragraph', text: 'An Initial Public Offering, commonly known as an IPO, is the process through which a private company offers its shares to the public for the first time and becomes listed on a stock exchange. Through an IPO, a company can raise capital from public investors and transition from private ownership to public market ownership.' },
          { type: 'heading', text: 'Why Companies Launch IPOs' },
          { type: 'paragraph', text: 'Companies may launch an IPO for several reasons, including business expansion, debt repayment, acquisitions, brand visibility, shareholder liquidity, or access to future capital markets. Once listed, the company becomes subject to public market rules, disclosure requirements, governance standards, and investor expectations.' },
          { type: 'heading', text: 'The IPO Process' },
          { type: 'paragraph', text: 'An IPO usually involves investment banks, underwriters, legal advisors, auditors, regulators, and the stock exchange. The company prepares offering documents providing information about its business model, financial performance, risks, management, industry, and valuation.' },
          { type: 'heading', text: 'IPO Risks for Investors' },
          { type: 'paragraph', text: 'For investors, IPOs can provide an opportunity to participate in a company\'s early public market journey. However, newly listed companies may have limited public trading history, uncertain valuation, lock-up effects, high volatility, or market hype. The IPO price may not always represent fair long-term value. A professional approach requires careful review of financial statements, valuation, business quality, growth prospects, and risk factors.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> An IPO is the first public sale of a company\'s shares, allowing the business to raise capital and become publicly traded on a stock exchange.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to subscribe to or trade any IPO or financial instrument. IPO investing involves substantial risk. Past IPO examples do not guarantee future performance. Conduct your own research and consult qualified professionals before making any financial decision.' },
        ]
      },
      { id: 'shares-equity-ownership', title: 'Shares, Equity, and Ownership', level: 'Beginner', summary: 'Understanding what owning a share really means.',
        content: [
          { type: 'image', src: 'images/SNRST005.jpg', alt: 'Shares Equity and Ownership' },
          { type: 'paragraph', text: 'Shares represent units of ownership in a company. When an investor buys shares of a listed company, they become a shareholder and own a portion of that business. This ownership is commonly referred to as equity.' },
          { type: 'heading', text: 'What Equity Means' },
          { type: 'paragraph', text: 'Equity represents the ownership interest of shareholders after liabilities are deducted from assets. In the stock market, share prices are influenced not only by accounting equity but also by earnings potential, growth expectations, market sentiment, industry outlook, and investor confidence.' },
          { type: 'heading', text: 'How Shareholders Benefit' },
          { type: 'paragraph', text: 'Shareholders may benefit through capital appreciation and dividends. Capital appreciation occurs when the market price of shares increases above the purchase price. Dividends are cash or stock distributions paid by some companies from profits, depending on board approval and company policy.' },
          { type: 'heading', text: 'Common vs Preferred Shares' },
          { type: 'paragraph', text: 'Owning shares may provide rights such as voting rights, participation in corporate actions, or entitlement to dividends if declared. Common shares usually provide ownership participation and voting rights, while preferred shares may provide priority dividends but limited voting rights. Shareholders participate in both the upside and downside of business performance.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Shares represent units of equity ownership in a company, giving shareholders economic participation in business performance, potential dividends, and market-based capital gains or losses.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or hold any share or financial instrument. Share ownership involves risk including possible loss of capital. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'investor-vs-trader', title: 'Investor vs Trader', level: 'Beginner', summary: 'Key differences in mindset, strategy, and time horizon.',
        content: [
          { type: 'image', src: 'images/SNRST006.jpg', alt: 'Investor vs Trader' },
          { type: 'paragraph', text: 'Investors and traders both participate in financial markets, but their objectives, time horizons, decision-making methods, and risk management styles are different.' },
          { type: 'heading', text: 'The Investor' },
          { type: 'paragraph', text: 'An investor usually focuses on long-term wealth creation. Investors analyze the quality, financial strength, valuation, competitive position, earnings potential, and growth prospects of a company. Their objective is often to hold shares for months, years, or even decades, benefiting from business growth, dividends, and compounding.' },
          { type: 'heading', text: 'The Trader' },
          { type: 'paragraph', text: 'A trader focuses on shorter-term price movements and may hold positions for minutes, hours, days, or weeks. Traders often use technical analysis, price action, volume, chart patterns, momentum, and market sentiment to identify entry and exit opportunities. The key question for a trader is whether the price movement offers a favorable risk-reward opportunity.' },
          { type: 'heading', text: 'Why Clarity Matters' },
          { type: 'paragraph', text: 'Both approaches can be professional if handled with discipline. Problems occur when people mix both approaches without clarity — for example, a trader who converts a losing short-term trade into a long-term investment, or an investor who panic-sells a strong business due to short-term volatility. A clear market role helps improve decision-making.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Investors focus on long-term business value and wealth creation, while traders focus on shorter-term price movement, timing, and risk-reward opportunities.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to adopt any specific strategy or trade any financial instrument. Both investing and trading involve risk. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'fa-beginners-stocks', title: 'Fundamental Analysis for Beginners', level: 'Beginner', summary: 'A starter guide to evaluating stocks using financial data.',
        content: [
          { type: 'image', src: 'images/SNRST007.jpg', alt: 'Fundamental Analysis for Beginners' },
          { type: 'paragraph', text: 'Fundamental analysis is the process of evaluating a company\'s financial health, business performance, valuation, management quality, industry position, and future growth potential. It helps investors understand whether a stock represents a strong business opportunity and whether its market price is reasonable compared to its underlying value.' },
          { type: 'heading', text: 'Where to Start' },
          { type: 'paragraph', text: 'At a beginner level, fundamental analysis starts with understanding what the company does, how it earns revenue, whether it is profitable, how much debt it carries, and whether it can generate consistent cash flow. A company with rising sales, improving profits, strong margins, manageable debt, and positive cash flow may be financially stronger than a company with weak earnings and heavy liabilities.' },
          { type: 'heading', text: 'Key Tools and Metrics' },
          { type: 'paragraph', text: 'Important tools include financial statements, earnings reports, valuation ratios, dividend history, industry comparison, and management commentary. Common metrics include earnings per share, price-to-earnings ratio, book value, return on equity, debt-to-equity ratio, profit margins, revenue growth, and dividend yield.' },
          { type: 'heading', text: 'Limitations of Fundamental Analysis' },
          { type: 'paragraph', text: 'Fundamental analysis does not guarantee that a stock price will rise immediately. A fundamentally strong company may remain undervalued for a long period, while a weak company may rise temporarily due to speculation. Therefore, investors often combine fundamentals with market timing, valuation discipline, and risk management.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Fundamental analysis evaluates the economic quality and intrinsic value of a company by studying financial performance, business strength, valuation, industry position, and future prospects.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or hold any stock or financial instrument. Strong fundamentals do not guarantee price appreciation. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'ta-beginners-stocks', title: 'Technical Analysis for Beginners', level: 'Beginner', summary: 'Using charts and price action to make trading decisions.',
        content: [
          { type: 'image', src: 'images/SNRST008.jpg', alt: 'Technical Analysis for Beginners' },
          { type: 'paragraph', text: 'Technical analysis is the study of price movement, volume, chart patterns, trends, and market behavior to identify potential trading opportunities. Unlike fundamental analysis, which focuses on business value and financial performance, technical analysis focuses on how price behaves in the market.' },
          { type: 'heading', text: 'The Core Idea' },
          { type: 'paragraph', text: 'The main idea behind technical analysis is that market price reflects the actions, expectations, emotions, and decisions of buyers and sellers. By studying price charts, traders attempt to understand market direction, momentum, support and resistance, trend strength, and potential reversal areas.' },
          { type: 'heading', text: 'Common Tools for Beginners' },
          { type: 'paragraph', text: 'Beginners commonly start with candlestick charts, trendlines, support and resistance, moving averages, volume, chart patterns, and indicators. These tools help traders identify whether a stock is trending upward, trending downward, consolidating, or showing signs of reversal. Technical analysis is especially useful for timing entries, exits, and stop-loss placement.' },
          { type: 'heading', text: 'Limitations' },
          { type: 'paragraph', text: 'Technical analysis is not a prediction machine. No pattern, indicator, or chart setup works all the time. False breakouts, sudden news, market manipulation, low liquidity, and emotional trading can lead to losses. Professional traders combine chart reading with risk management, position sizing, market context, and emotional control.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Technical analysis is a market-based analytical approach that studies price, volume, trend, and behavior to support timing, trade planning, and risk management decisions.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to use any technical strategy or trade any financial instrument. Technical analysis involves uncertainty and does not guarantee future price movement. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'what-is-eps', title: 'What is EPS and Why It Matters?', level: 'Beginner', summary: 'Earnings Per Share explained and why investors watch it closely.',
        content: [
          { type: 'image', src: 'images/SNRST009.jpg', alt: 'What is EPS and Why It Matters' },
          { type: 'paragraph', text: 'Earnings Per Share, commonly known as EPS, is one of the most important profitability metrics used in stock market analysis. It shows how much profit a company earns for each outstanding share of common stock.' },
          { type: 'heading', text: 'How EPS is Calculated' },
          { type: 'paragraph', text: 'EPS is generally calculated by dividing net income available to common shareholders by the weighted average number of outstanding shares. A rising EPS may indicate improving profitability, growing earnings, or efficient capital use. A declining EPS may signal weaker business performance, rising expenses, falling revenue, or shareholder dilution.' },
          { type: 'heading', text: 'Basic vs Diluted EPS' },
          { type: 'paragraph', text: 'There are different types of EPS, including basic EPS and diluted EPS. Basic EPS uses current outstanding shares, while diluted EPS considers the potential impact of convertible securities, stock options, or other instruments that may increase the number of shares in the future. Diluted EPS is often considered more conservative and is widely used in professional analysis.' },
          { type: 'heading', text: 'Quality of Earnings' },
          { type: 'paragraph', text: 'EPS is important because it is used in valuation ratios such as the Price-to-Earnings ratio. However, EPS can be affected by accounting policies, one-time gains or losses, share buybacks, non-operating income, or unusual expenses. Professional analysts study the quality of earnings, not just the reported EPS number.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> EPS measures a company\'s profit attributable to each share and serves as a key indicator of profitability, earnings growth, and valuation relevance.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or hold any stock or financial instrument. EPS growth does not guarantee share price appreciation or future profitability. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'understanding-pe-ratio', title: 'Understanding P/E Ratio', level: 'Beginner', summary: 'How to interpret the Price-to-Earnings ratio when evaluating stocks.',
        content: [
          { type: 'image', src: 'images/SNRST010.jpg', alt: 'Understanding P/E Ratio' },
          { type: 'paragraph', text: 'The Price-to-Earnings ratio, commonly known as the P/E ratio, is a widely used valuation metric in stock market analysis. It compares a company\'s share price with its earnings per share and helps investors understand how much the market is willing to pay for each unit of company earnings.' },
          { type: 'heading', text: 'How to Calculate P/E' },
          { type: 'paragraph', text: 'The P/E ratio is calculated by dividing the market price per share by earnings per share. For example, if a stock is trading at 100 and its EPS is 10, the P/E ratio is 10. This means investors are paying 10 times the company\'s annual earnings per share.' },
          { type: 'heading', text: 'Interpreting High and Low P/E' },
          { type: 'paragraph', text: 'A high P/E ratio may indicate that investors expect strong future growth or high business quality, but it may also suggest the stock is expensive or overvalued. A low P/E ratio may indicate undervaluation, but it may also reflect weak growth, business risk, or declining earnings. The P/E ratio is most useful when compared with similar companies in the same industry and the company\'s own historical valuation range.' },
          { type: 'heading', text: 'Trailing vs Forward P/E' },
          { type: 'paragraph', text: 'Trailing P/E uses past earnings, while forward P/E uses expected future earnings. Forward P/E can be useful, but it depends on forecasts which may be wrong. Professional investors combine P/E with earnings quality, growth rate, debt levels, cash flow, return on equity, and macroeconomic conditions.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> The P/E ratio is a valuation multiple that shows how the market prices a company\'s earnings relative to its share price, but it must be interpreted within business, sector, and growth context.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or hold any stock or financial instrument. The P/E ratio is only one valuation tool and may be misleading if used in isolation. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'dividend-yield', title: 'Dividend Yield Explained', level: 'Beginner', summary: 'What dividends are and how to calculate dividend yield.',
        content: [
          { type: 'image', src: 'images/SNRST011.jpg', alt: 'Dividend Yield Explained' },
          { type: 'paragraph', text: 'Dividend yield is a financial ratio that shows how much dividend income a shareholder receives relative to the current market price of a stock. It is commonly used by income-focused investors to evaluate the cash return generated by a dividend-paying company.' },
          { type: 'heading', text: 'How Dividend Yield is Calculated' },
          { type: 'paragraph', text: 'Dividend yield is calculated by dividing the annual dividend per share by the current share price and multiplying by 100. For example, if a company pays an annual dividend of 5 per share and the stock price is 100, the dividend yield is 5%. Companies with stable earnings, strong cash flow, and mature business models are often more likely to pay regular dividends.' },
          { type: 'heading', text: 'The Dividend Trap' },
          { type: 'paragraph', text: 'A high dividend yield is not always a positive sign. Sometimes the yield becomes high because the share price has fallen sharply due to business weakness, declining earnings, or market concern. This is known as a dividend trap. Investors must analyze whether the dividend is sustainable.' },
          { type: 'heading', text: 'Analyzing Dividend Sustainability' },
          { type: 'paragraph', text: 'Important factors in dividend analysis include payout ratio, earnings stability, free cash flow, debt levels, dividend history, industry conditions, and management policy. A company that pays dividends from strong cash flow is generally more reliable than one paying dividends despite weak profitability. Dividend yield should be evaluated as part of a complete investment analysis.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Dividend yield measures the annual dividend income generated by a stock relative to its market price, but sustainability depends on earnings quality, cash flow, and financial strength.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or hold any stock or financial instrument. Dividends are not guaranteed and may be reduced or cancelled at any time. High dividend yield may indicate elevated risk. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'market-cap', title: 'Market Capitalization', level: 'Beginner', summary: 'Small cap, mid cap, and large cap stocks — what the differences mean.',
        content: [
          { type: 'image', src: 'images/SNRST012.jpg', alt: 'Market Capitalization' },
          { type: 'paragraph', text: 'Market capitalization, often called market cap, represents the total market value of a publicly listed company\'s outstanding shares. It is calculated by multiplying the current share price by the total number of outstanding shares.' },
          { type: 'heading', text: 'Market Cap Categories' },
          { type: 'paragraph', text: 'Market cap helps investors understand the size of a company. Companies are commonly classified as large-cap, mid-cap, small-cap, or micro-cap, depending on their market value. Large-cap companies are usually more established, with stronger market presence, better liquidity, and more institutional participation. Mid-cap companies may offer a balance between growth potential and business maturity. Small-cap companies may offer higher growth opportunities but often carry higher risk, lower liquidity, and greater volatility.' },
          { type: 'heading', text: 'What Market Cap Does Not Tell You' },
          { type: 'paragraph', text: 'Market cap does not show whether a company is cheap or expensive by itself. A company with a large market cap may still be overvalued or undervalued depending on earnings, assets, growth, cash flow, and industry position. Similarly, a small-cap company may be attractive or risky depending on business fundamentals.' },
          { type: 'paragraph', text: 'Professional investors use market cap to understand company scale, liquidity profile, index eligibility, institutional interest, and portfolio allocation suitability.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Market capitalization measures the total market value of a company\'s outstanding equity and helps classify company size, liquidity profile, and investment risk category.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or hold any stock or financial instrument. Market cap is not a complete measure of company value or investment quality. Large-cap stocks can decline significantly, and small-cap stocks may involve higher volatility. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'financial-statements-intro', title: 'Understanding Financial Statements', level: 'Intermediate', summary: 'Reading the balance sheet, income statement, and cash flow statement.',
        content: [
          { type: 'image', src: 'images/SNRST013.jpg', alt: 'Understanding Financial Statements' },
          { type: 'paragraph', text: 'Financial statements are formal reports that show a company\'s financial performance, financial position, and cash flow activity. They are essential tools for fundamental analysis and help investors evaluate the health and quality of a business.' },
          { type: 'heading', text: 'The Income Statement' },
          { type: 'paragraph', text: 'The income statement shows revenue, expenses, and profit over a specific period. It helps investors understand whether the company is growing sales, controlling costs, and generating profit.' },
          { type: 'heading', text: 'The Balance Sheet' },
          { type: 'paragraph', text: 'The balance sheet shows assets, liabilities, and shareholders\' equity at a specific point in time. It helps investors analyze the company\'s financial strength, debt levels, liquidity, and capital structure.' },
          { type: 'heading', text: 'The Cash Flow Statement' },
          { type: 'paragraph', text: 'The cash flow statement shows how cash moves in and out of the business. It is divided into operating cash flow, investing cash flow, and financing cash flow. This statement is especially important because a company can report accounting profit but still face cash flow problems.' },
          { type: 'heading', text: 'Connecting the Three Statements' },
          { type: 'paragraph', text: 'Professional investors connect all three statements to understand the complete business picture. Rising profits are more reliable if supported by strong operating cash flow. Financial statements allow investors to calculate important ratios such as profit margin, return on equity, current ratio, debt-to-equity, and free cash flow.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Financial statements provide structured information about a company\'s profitability, financial position, liquidity, cash generation, and capital structure, forming the foundation of fundamental analysis.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, accounting, or investment advice. Financial statements may be affected by accounting policies, estimates, management assumptions, and reporting standards. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'snr-stocks', title: 'Support and Resistance in Stock Trading', level: 'Intermediate', summary: 'Applying S&R principles to stock chart analysis.',
        content: [
          { type: 'image', src: 'images/SNRST014.jpg', alt: 'Support and Resistance in Stock Trading' },
          { type: 'paragraph', text: 'Support and resistance are core concepts in technical analysis. They help traders identify important price levels where buying or selling pressure may appear.' },
          { type: 'heading', text: 'Support' },
          { type: 'paragraph', text: 'Support is a price area where demand may become strong enough to prevent the stock from falling further. It is often formed near previous lows, consolidation zones, moving averages, trendlines, or high-volume areas. Traders watch support levels because price may bounce from these areas if buyers become active.' },
          { type: 'heading', text: 'Resistance' },
          { type: 'paragraph', text: 'Resistance is a price area where selling pressure may become strong enough to prevent the stock from rising further. It is often formed near previous highs, supply zones, psychological price levels, or areas where sellers previously entered the market. Support and resistance are better understood as zones rather than exact prices.' },
          { type: 'heading', text: 'Role Reversal' },
          { type: 'paragraph', text: 'When price breaks above resistance with strong volume and momentum, the level may turn into future support. Similarly, when price breaks below support, the level may turn into future resistance. This behavior is known as role reversal. Support and resistance help traders plan entries, exits, stop-loss levels, and risk-reward ratios, but they should be used with volume, candlestick behavior, and broader market context for confirmation.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Support and resistance represent key price zones where market participants have historically shown buying or selling interest, making them important tools for trade planning and risk management.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to use any specific technical level or strategy. Support and resistance levels are analytical estimates and may fail at any time. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'risk-management-stocks', title: 'Risk Management in Stock Market', level: 'Intermediate', summary: 'Protecting capital and managing downside in stock trading.',
        content: [
          { type: 'image', src: 'images/SNRST015.jpg', alt: 'Risk Management in Stock Market' },
          { type: 'paragraph', text: 'Risk management is one of the most important disciplines in stock market investing and trading. It is the process of protecting capital, controlling losses, managing exposure, and making decisions based on a structured plan rather than emotions.' },
          { type: 'heading', text: 'Capital Allocation' },
          { type: 'paragraph', text: 'Risk management begins with capital allocation. Investors should decide how much capital to allocate to the stock market, how much to invest in each company, and how much exposure to maintain across sectors. Concentrating too much capital in one stock, sector, or theme can increase portfolio risk significantly.' },
          { type: 'heading', text: 'Position Sizing and Stop-Loss' },
          { type: 'paragraph', text: 'For traders, position sizing and stop-loss planning are critical. Before entering a trade, a trader should know the entry level, invalidation level, target area, risk amount, and risk-reward ratio. Losses are part of trading, but uncontrolled losses can damage capital and confidence.' },
          { type: 'heading', text: 'Broader Risk Controls' },
          { type: 'paragraph', text: 'Risk management also includes diversification, liquidity awareness, avoiding overtrading, understanding market cycles, reviewing company fundamentals, and maintaining emotional discipline. Investors should also consider event risks such as earnings announcements, regulatory changes, interest rate decisions, and geopolitical developments. Professional risk management does not eliminate losses — its purpose is to ensure that no single mistake can seriously damage long-term financial stability.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Risk management is the disciplined framework used to control capital exposure, limit losses, manage uncertainty, and support sustainable participation in the stock market.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or hold any stock or financial instrument. Risk management can reduce exposure but cannot eliminate market risk or guarantee profit. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
    ]
  },

  // ── COMMODITIES ────────────────────────────────────────────────────────────
  {
    id: 'commodities', icon: '🥇', title: 'Commodities',
    desc: 'Gold, silver, oil, supply and demand, inflation, and safe-haven assets.',
    topics: [
      { id: 'what-are-commodities', title: 'What are Commodities?', level: 'Beginner', summary: 'An overview of commodity markets and the assets traded within them.',
        content: [
          { type: 'image', src: 'images/SNRCOM001.jpg', alt: 'What are Commodities' },
          { type: 'paragraph', text: 'Commodities are basic physical goods that are traded in financial markets. These goods are usually raw materials or natural resources used in daily life, business, manufacturing, agriculture, and energy production. Common examples include gold, silver, crude oil, natural gas, wheat, corn, coffee, sugar, and cotton.' },
          { type: 'heading', text: 'Role of Commodity Markets' },
          { type: 'paragraph', text: 'Commodity markets are important because they connect global supply and demand. Producers, businesses, investors, and traders participate in these markets for different reasons. Some use commodities to manage business risk, while others trade them to benefit from price movements.' },
          { type: 'heading', text: 'Categories of Commodities' },
          { type: 'paragraph', text: 'Commodities are generally divided into different categories such as metals, energy, and agricultural products. Metals include gold, silver, copper, and platinum. Energy commodities include crude oil, natural gas, and gasoline. Agricultural commodities include wheat, corn, coffee, sugar, and cotton.' },
          { type: 'heading', text: 'What Moves Commodity Prices' },
          { type: 'paragraph', text: 'Commodity prices can move due to supply shortages, demand changes, geopolitical events, inflation, weather conditions, currency strength, central bank policies, and global economic growth. For example, oil prices may rise during supply disruptions, while gold may attract attention during periods of economic uncertainty.' },
          { type: 'paragraph', text: 'Commodities are widely traded through spot markets, futures contracts, exchange-traded products, and derivatives. However, commodity trading can be highly volatile and requires proper knowledge, discipline, and risk management.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Commodities are raw materials or basic goods that are traded in global markets, such as gold, oil, silver, wheat, and natural gas.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any commodity or financial instrument. Commodity trading involves significant risk due to price volatility, leverage, and global market uncertainty. Past performance does not guarantee future results. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'hard-vs-soft', title: 'Hard vs Soft Commodities', level: 'Beginner', summary: 'The difference between mined and grown commodities.',
        content: [
          { type: 'image', src: 'images/SNRCOM002.jpg', alt: 'Hard vs Soft Commodities' },
          { type: 'paragraph', text: 'Commodities are commonly divided into two main categories: hard commodities and soft commodities. Understanding the difference between them helps traders and investors better analyze market behavior, price drivers, and risk factors.' },
          { type: 'heading', text: 'Hard Commodities' },
          { type: 'paragraph', text: 'Hard commodities are natural resources that are mined or extracted from the earth. Examples include gold, silver, copper, crude oil, natural gas, platinum, and other metals or energy products. These commodities are often linked to industrial demand, global growth, mining activity, energy consumption, and geopolitical developments.' },
          { type: 'heading', text: 'Soft Commodities' },
          { type: 'paragraph', text: 'Soft commodities are agricultural products or goods that are grown or produced through farming. Examples include wheat, corn, coffee, sugar, cotton, cocoa, and soybeans. These commodities are strongly affected by weather conditions, crop production, seasonal cycles, supply disruptions, global consumption, and agricultural policies.' },
          { type: 'heading', text: 'Key Differences in Price Drivers' },
          { type: 'paragraph', text: 'Hard commodities often respond to industrial activity, inflation expectations, interest rates, and global economic conditions. Soft commodities can be more sensitive to climate, harvest quality, disease, transportation issues, and seasonal supply. A drought, flood, or unexpected crop shortage can create strong price movement in agricultural markets.' },
          { type: 'paragraph', text: 'Both hard and soft commodities can provide trading opportunities, but they require different types of analysis. A professional trader must understand the unique drivers of each commodity before making decisions.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Hard commodities are mined or extracted, such as gold and oil. Soft commodities are grown, such as wheat, coffee, and cotton.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any commodity or financial instrument. Hard and soft commodities can be highly volatile and may react differently to weather, economic conditions, and geopolitical events. Trading commodities involves risk, including possible loss of capital. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'intro-gold-trading', title: 'Introduction to Gold Trading', level: 'Beginner', summary: 'How gold is traded, why it matters, and how to get started.',
        content: [
          { type: 'image', src: 'images/SNRCOM003.jpg', alt: 'Introduction to Gold Trading' },
          { type: 'paragraph', text: 'Gold is one of the most widely followed commodities in the world. It has historically been used as a store of value, a hedge against uncertainty, and an important asset in global financial markets. Gold is traded by investors, institutions, central banks, and short-term traders.' },
          { type: 'heading', text: 'How Gold is Traded' },
          { type: 'paragraph', text: 'Gold trading involves buying or selling gold-related instruments to benefit from price movements. Traders may access gold through spot gold, futures contracts, exchange-traded funds, CFDs, or physical gold, depending on the market and platform available to them.' },
          { type: 'heading', text: 'What Influences Gold Prices' },
          { type: 'paragraph', text: 'Gold prices are influenced by several important factors, including inflation expectations, interest rates, US Dollar strength, central bank policies, geopolitical tensions, global risk sentiment, and demand from investors or jewelry markets. When uncertainty increases, gold may attract demand because many market participants consider it a defensive asset.' },
          { type: 'heading', text: 'Gold and the US Dollar' },
          { type: 'paragraph', text: 'One of the key relationships in gold trading is its connection with the US Dollar and interest rates. Since gold is commonly priced in US Dollars, a stronger Dollar can sometimes put pressure on gold prices, while a weaker Dollar may support gold. Higher interest rates may also reduce gold\'s appeal because gold does not generate interest income.' },
          { type: 'paragraph', text: 'Gold can be attractive for both long-term investors and short-term traders, but it can also be volatile. Sharp price movements may occur during economic data releases, central bank announcements, geopolitical events, or major market shocks. Professional gold trading requires technical analysis, fundamental understanding, and proper risk management.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Gold trading means buying or selling gold-related instruments to benefit from changes in gold prices.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade gold or any financial instrument. Gold trading involves risk. Prices can move sharply due to interest rates, inflation, geopolitical events, and market sentiment. Past performance does not guarantee future results. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'intro-silver-trading', title: 'Introduction to Silver Trading', level: 'Beginner', summary: 'Silver as an industrial and precious metal — trading the white metal.',
        content: [
          { type: 'image', src: 'images/SNRCOM004.jpg', alt: 'Introduction to Silver Trading' },
          { type: 'paragraph', text: 'Silver is a precious metal that is actively traded in global commodity markets. Like gold, silver is considered a store of value, but it also has strong industrial demand. This combination makes silver unique because its price can be influenced by both investment demand and industrial usage.' },
          { type: 'heading', text: 'Industrial and Investment Demand' },
          { type: 'paragraph', text: 'Silver is used in electronics, solar panels, medical equipment, batteries, jewelry, and various industrial applications. Because of this, silver prices may react not only to inflation and market uncertainty but also to industrial growth, manufacturing demand, and technological trends.' },
          { type: 'heading', text: 'How Silver is Traded' },
          { type: 'paragraph', text: 'Traders can access silver through spot silver, futures contracts, exchange-traded products, CFDs, or physical silver. Short-term traders often focus on price action, chart patterns, support and resistance, and market volatility. Long-term investors may study industrial demand, supply conditions, inflation trends, and monetary policy.' },
          { type: 'heading', text: 'Silver Volatility and Risk' },
          { type: 'paragraph', text: 'Silver is often more volatile than gold. This means it can move faster and with larger percentage changes. While this may create trading opportunities, it also increases risk. Traders must be careful with position sizing, leverage, and stop-loss placement.' },
          { type: 'paragraph', text: 'Silver may also be influenced by the US Dollar, interest rates, mining supply, global economic growth, and investor sentiment. During periods of uncertainty, silver may attract safe-haven demand, but during economic expansion, it may also benefit from industrial demand.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Silver trading means buying or selling silver-related instruments to benefit from price movements in the silver market.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade silver or any financial instrument. Silver prices can be highly volatile and may react to industrial demand, inflation, interest rates, and market sentiment. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'intro-oil-trading', title: 'Introduction to Crude Oil Trading', level: 'Beginner', summary: 'How crude oil markets work and what drives price movements.',
        content: [
          { type: 'image', src: 'images/SNRCOM005.jpg', alt: 'Introduction to Crude Oil Trading' },
          { type: 'paragraph', text: 'Crude oil is one of the most important energy commodities in the world. It plays a major role in transportation, manufacturing, power generation, and global economic activity. Because of its importance, crude oil is actively traded by institutions, producers, investors, and short-term traders.' },
          { type: 'heading', text: 'How Crude Oil is Traded' },
          { type: 'paragraph', text: 'Crude oil trading involves buying or selling oil-related instruments to benefit from price movements. Common oil benchmarks include WTI crude oil and Brent crude oil. WTI is commonly associated with the US market, while Brent is widely used as a global oil pricing benchmark.' },
          { type: 'heading', text: 'What Moves Oil Prices' },
          { type: 'paragraph', text: 'Oil prices are strongly affected by supply and demand. When global demand rises or supply becomes restricted, oil prices may increase. When supply is high or demand weakens, oil prices may decline. Factors such as OPEC+ production decisions, geopolitical tensions, inventory reports, economic growth, transportation demand, and currency movements can all influence oil prices.' },
          { type: 'heading', text: 'Volatility and Risk' },
          { type: 'paragraph', text: 'Crude oil is known for sharp price movements, especially during major news events. Reports such as weekly inventory data, production announcements, conflicts in oil-producing regions, and global economic updates can create strong volatility.' },
          { type: 'paragraph', text: 'Oil trading can be suitable for experienced traders who understand commodity cycles, technical analysis, news impact, and risk management. However, it can be risky for beginners due to fast price movement, leverage, spreads, and sudden market reactions.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Crude oil trading means buying or selling oil-related instruments to benefit from changes in oil prices.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade crude oil or any financial instrument. Oil prices can move sharply due to supply disruptions, OPEC+ decisions, geopolitical events, and economic conditions. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'factors-gold-prices', title: 'Factors Affecting Gold Prices', level: 'Intermediate', summary: 'The key drivers behind gold price movements.',
        content: [
          { type: 'image', src: 'images/SNRCOM006.jpg', alt: 'Factors Affecting Gold Prices' },
          { type: 'paragraph', text: 'Gold prices are influenced by a wide range of economic, financial, and geopolitical factors. Understanding these factors helps traders and investors analyze why gold moves and what may affect future price direction.' },
          { type: 'heading', text: 'Interest Rates' },
          { type: 'paragraph', text: 'One of the most important factors affecting gold is interest rates. When interest rates rise, gold may become less attractive because it does not generate interest income. When interest rates fall or are expected to fall, gold may become more attractive for investors.' },
          { type: 'heading', text: 'Inflation' },
          { type: 'paragraph', text: 'Gold is often viewed as a hedge against inflation because it may preserve value when the purchasing power of currency declines. During periods of high inflation or inflation uncertainty, demand for gold may increase.' },
          { type: 'heading', text: 'US Dollar Strength' },
          { type: 'paragraph', text: 'Since gold is commonly priced in US Dollars, a stronger Dollar can make gold more expensive for buyers using other currencies, which may put pressure on prices. A weaker Dollar may support gold demand.' },
          { type: 'heading', text: 'Geopolitics and Safe-Haven Demand' },
          { type: 'paragraph', text: 'Geopolitical tension, financial market stress, banking concerns, and economic uncertainty can also increase demand for gold as a safe-haven asset. In uncertain times, investors may move toward gold to reduce exposure to riskier assets.' },
          { type: 'heading', text: 'Central Banks and Supply' },
          { type: 'paragraph', text: 'Central bank activity is another key factor. When central banks buy gold, it can support long-term demand. On the supply side, mining production, refining, and physical demand from jewelry and investment markets may also influence prices.' },
          { type: 'paragraph', text: 'Gold price movement is rarely caused by one factor alone. Professional traders analyze the combined impact of interest rates, inflation, the US Dollar, global risk sentiment, and technical price structure.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Gold prices are affected by interest rates, inflation, the US Dollar, central banks, global uncertainty, and supply and demand.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade gold or any financial instrument. No factor or analysis can guarantee future gold price movement. Gold can be volatile and may react unexpectedly to news and market conditions. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'factors-oil-prices', title: 'Factors Affecting Oil Prices', level: 'Intermediate', summary: 'Supply, demand, geopolitics, and OPEC\'s role in oil pricing.',
        content: [
          { type: 'image', src: 'images/SNRCOM007.jpg', alt: 'Factors Affecting Oil Prices' },
          { type: 'paragraph', text: 'Oil prices are mainly driven by supply and demand, but many global factors can influence the balance between them. Because crude oil is essential for transportation, industry, and energy production, its price is closely connected to the global economy.' },
          { type: 'heading', text: 'Supply-Side Factors' },
          { type: 'paragraph', text: 'On the supply side, oil prices can be affected by production levels, OPEC+ decisions, drilling activity, sanctions, conflicts, natural disasters, and transportation disruptions. If supply becomes limited while demand remains strong, oil prices may rise. If supply increases or production exceeds demand, prices may fall.' },
          { type: 'heading', text: 'Demand-Side Factors' },
          { type: 'paragraph', text: 'On the demand side, global economic growth is a major factor. When economies are expanding, demand for transportation, manufacturing, and energy usually increases. This can support oil prices. During economic slowdowns or recessions, demand may weaken and put pressure on prices.' },
          { type: 'heading', text: 'Inventory Reports' },
          { type: 'paragraph', text: 'Inventory reports are also important. If crude oil inventories rise more than expected, it may indicate weaker demand or excess supply. If inventories fall, it may suggest stronger demand or tighter supply conditions.' },
          { type: 'heading', text: 'Other Influences' },
          { type: 'paragraph', text: 'Geopolitical events can create sudden volatility in oil markets, especially when they involve major oil-producing regions or shipping routes. Currency movements also matter because crude oil is commonly priced in US Dollars. Seasonal demand such as travel seasons, heating demand, and industrial cycles may also influence consumption patterns.' },
          { type: 'paragraph', text: 'Professional oil traders study supply reports, demand forecasts, inventory data, geopolitical risks, economic indicators, and technical chart structure before making trading decisions.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Oil prices are affected by supply, demand, OPEC+ decisions, inventories, economic growth, geopolitical events, and currency movements.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade crude oil or any financial instrument. Oil markets can be highly volatile and unpredictable. No analysis can guarantee any specific trading outcome. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'commodity-cycles', title: 'Commodity Market Cycles', level: 'Intermediate', summary: 'Understanding the cyclical nature of commodity markets.',
        content: [
          { type: 'image', src: 'images/SNRCOM008.jpg', alt: 'Commodity Market Cycles' },
          { type: 'paragraph', text: 'Commodity markets often move in cycles. These cycles are driven by changes in supply, demand, production capacity, economic growth, inflation, and investor sentiment. Understanding commodity market cycles helps traders and investors identify broader market conditions and avoid emotional decision-making.' },
          { type: 'heading', text: 'How a Commodity Cycle Works' },
          { type: 'paragraph', text: 'A commodity cycle usually includes periods of rising prices, peak demand, oversupply, falling prices, and recovery. When demand is strong and supply is limited, commodity prices may rise. Higher prices can encourage producers to increase production. Over time, increased production may create excess supply, which can push prices lower.' },
          { type: 'paragraph', text: 'When prices fall too much, producers may reduce output, delay projects, or cut investment. This can eventually reduce supply and create conditions for prices to recover. This repeating process is one reason commodity markets often move in long-term cycles.' },
          { type: 'heading', text: 'Cycle Lengths Vary by Commodity' },
          { type: 'paragraph', text: 'Different commodities may have different cycle lengths. Agricultural commodities can be affected by seasonal cycles and weather patterns, while metals and energy commodities may follow longer investment and production cycles. For example, mining projects and oil production investments can take years to develop.' },
          { type: 'heading', text: 'Macroeconomic Influence' },
          { type: 'paragraph', text: 'Commodity cycles are also influenced by macroeconomic conditions. Inflation, interest rates, currency strength, global growth, industrial demand, and geopolitical events can all accelerate or slow down a cycle. Traders use commodity cycle analysis to understand the bigger picture, but cycles are not perfect and do not always repeat exactly.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Commodity market cycles are repeated phases of rising and falling prices caused by changes in supply, demand, production, and economic conditions.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any commodity or financial instrument. Commodity cycles can be difficult to predict and may change due to unexpected events. Historical cycles do not guarantee future price behavior. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'inflation-commodities', title: 'Inflation and Its Impact on Commodities', level: 'Intermediate', summary: 'Why commodities often rise during inflationary periods.',
        content: [
          { type: 'image', src: 'images/SNRCOM009.jpg', alt: 'Inflation and Its Impact on Commodities' },
          { type: 'paragraph', text: 'Inflation is the general rise in prices of goods and services over time. It reduces the purchasing power of money and can have a major impact on commodity markets. Since commodities are physical goods used in the real economy, they are often closely connected to inflation trends.' },
          { type: 'heading', text: 'How Inflation Affects Commodities' },
          { type: 'paragraph', text: 'When inflation rises, commodity prices may also increase because raw materials, energy, transportation, labor, and production costs become more expensive. For example, higher crude oil prices can increase transportation and manufacturing costs, which may contribute to broader inflation.' },
          { type: 'heading', text: 'Gold and Inflation' },
          { type: 'paragraph', text: 'Some commodities, especially gold, are often viewed as inflation-sensitive assets. During inflationary periods, investors may look toward gold or other real assets to protect purchasing power. However, gold does not always rise during inflation because interest rates, the US Dollar, and central bank policy also play an important role.' },
          { type: 'heading', text: 'Energy and Agricultural Commodities' },
          { type: 'paragraph', text: 'Energy commodities such as oil and natural gas can both influence and respond to inflation. Rising energy prices can increase inflation, while high inflation can affect consumer demand and economic activity. Agricultural commodities may also be affected by inflation through higher fertilizer, fuel, labor, and transportation costs.' },
          { type: 'heading', text: 'Inflation and Central Bank Decisions' },
          { type: 'paragraph', text: 'For traders, inflation data is important because it can influence central bank decisions. If inflation is high, central banks may raise interest rates, which can affect currencies, gold, oil, and other commodities.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Inflation can increase commodity prices because raw materials, energy, and production costs become more expensive. It can also change investor demand for assets like gold.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any commodity or financial instrument. Inflation and commodity prices are influenced by many factors including central bank policy, interest rates, and supply conditions. No inflation-based analysis can guarantee future market direction. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'safe-haven-assets', title: 'Safe Haven Assets Explained', level: 'Beginner', summary: 'Assets that hold value during market uncertainty.',
        content: [
          { type: 'image', src: 'images/SNRCOM010.jpg', alt: 'Safe Haven Assets Explained' },
          { type: 'paragraph', text: 'Safe haven assets are assets that investors often consider during periods of uncertainty, market stress, economic weakness, geopolitical tension, or financial instability. These assets are called "safe haven" because they may help preserve value when riskier markets are under pressure.' },
          { type: 'heading', text: 'Gold as a Safe Haven' },
          { type: 'paragraph', text: 'Gold is one of the most well-known safe haven assets. Many investors turn to gold during uncertain times because it has a long history as a store of value. It is not directly tied to the performance of a single company or government, which makes it attractive during periods of financial concern.' },
          { type: 'heading', text: 'Other Safe Haven Assets' },
          { type: 'paragraph', text: 'Other assets sometimes considered safe havens include certain government bonds, the US Dollar, Swiss Franc, Japanese Yen, and cash equivalents. However, safe haven behavior can change depending on the market environment.' },
          { type: 'heading', text: 'Safe Haven Does Not Mean Risk-Free' },
          { type: 'paragraph', text: 'It is important to understand that "safe haven" does not mean risk-free. Even safe haven assets can decline in value. For example, gold may fall if interest rates rise sharply or if the US Dollar strengthens. Government bonds may lose value when interest rates increase.' },
          { type: 'heading', text: 'When Safe Haven Demand Increases' },
          { type: 'paragraph', text: 'Safe haven demand usually increases when investors become defensive. This may happen during stock market declines, banking concerns, wars, recessions, inflation uncertainty, or global financial stress. Professional traders do not buy safe haven assets blindly. They analyze the reason behind the market uncertainty, interest rates, currency movement, and technical price structure before making decisions.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Safe haven assets are assets that investors may prefer during uncertain or risky market conditions, but they are not completely risk-free.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any asset or financial instrument. Safe haven assets are not guaranteed to protect capital and may decline in value. The term "safe haven" should not be understood as "risk-free." Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'supply-demand-commodities', title: 'Supply and Demand in Commodity Markets', level: 'Beginner', summary: 'How supply and demand fundamentals drive commodity prices.',
        content: [
          { type: 'image', src: 'images/SNRCOM011.jpg', alt: 'Supply and Demand in Commodity Markets' },
          { type: 'paragraph', text: 'Supply and demand are the foundation of commodity price movement. Commodity prices rise and fall based on the balance between how much of a commodity is available and how much buyers need or want.' },
          { type: 'heading', text: 'Supply' },
          { type: 'paragraph', text: 'Supply refers to the amount of a commodity available in the market. It can be affected by production levels, mining output, farming conditions, inventories, transportation, weather, geopolitical events, and government policies. If supply decreases while demand remains strong, prices may rise.' },
          { type: 'heading', text: 'Demand' },
          { type: 'paragraph', text: 'Demand refers to how much of a commodity buyers are willing to purchase. Demand can be influenced by economic growth, industrial activity, consumer behavior, seasonal needs, technology, and global trade. If demand increases while supply is limited, prices may move higher.' },
          { type: 'heading', text: 'Real-World Examples' },
          { type: 'paragraph', text: 'For example, crude oil prices may rise if demand increases while production is restricted. Gold prices may rise if investors increase demand during uncertain times. Agricultural prices may rise if bad weather reduces crop supply.' },
          { type: 'heading', text: 'Markets Price in Expectations' },
          { type: 'paragraph', text: 'Supply and demand analysis is important because commodities are directly connected to the real economy. However, price movement is not always simple. Markets often react to expectations before actual supply or demand changes occur. Traders may price in future shortages, future demand growth, or expected policy changes.' },
          { type: 'paragraph', text: 'Professional traders combine supply and demand analysis with technical analysis, market sentiment, inventory data, and macroeconomic conditions.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Commodity prices usually rise when demand is strong and supply is limited. Prices usually fall when supply is high and demand is weak.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any commodity or financial instrument. Supply and demand conditions can change quickly due to economic events, weather, and geopolitical developments. Analysis does not guarantee future price movement. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'commodity-futures', title: 'Commodity Futures Explained', level: 'Intermediate', summary: 'What futures contracts are and how they work in commodity markets.',
        content: [
          { type: 'image', src: 'images/SNRCOM012.jpg', alt: 'Commodity Futures Explained' },
          { type: 'paragraph', text: 'Commodity futures are financial contracts that allow traders and investors to buy or sell a commodity at a predetermined price for delivery or settlement at a future date. Futures contracts are commonly used in markets such as crude oil, gold, silver, natural gas, wheat, corn, and other commodities.' },
          { type: 'heading', text: 'How Futures Contracts Work' },
          { type: 'paragraph', text: 'A futures contract specifies the commodity, quantity, quality, delivery month, and contract terms. In practice, many traders do not take physical delivery of the commodity. Instead, they trade the price movement of the futures contract before expiry.' },
          { type: 'heading', text: 'Hedgers and Speculators' },
          { type: 'paragraph', text: 'Commodity futures are used by two main types of participants: hedgers and speculators. Hedgers use futures to manage price risk. For example, an airline may use oil futures to protect against rising fuel prices. A farmer may use agricultural futures to manage the risk of falling crop prices. Speculators trade futures to benefit from price movement without wanting the physical commodity.' },
          { type: 'heading', text: 'Expiration and Complexity' },
          { type: 'paragraph', text: 'One important feature of futures is expiration. Each contract has a specific expiry date, and traders must understand contract rollover, settlement rules, margin requirements, and price differences between contract months.' },
          { type: 'paragraph', text: 'Commodity futures can be powerful tools, but they are more complex than simple spot trading. Professional traders must understand contract specifications, margin, volatility, liquidity, and risk before participating.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Commodity futures are contracts to buy or sell a commodity at a set price for a future date. They are used for hedging, speculation, and price risk management.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade commodity futures or any financial instrument. Futures trading involves substantial risk, including leverage, margin requirements, expiry, and rapid price movement. Losses can be significant. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'spot-vs-futures-commodity', title: 'Spot vs Futures Commodity Trading', level: 'Intermediate', summary: 'The difference between spot price and futures contracts.',
        content: [
          { type: 'image', src: 'images/SNRCOM013.jpg', alt: 'Spot vs Futures Commodity Trading' },
          { type: 'paragraph', text: 'Spot and futures trading are two common ways to participate in commodity markets. Both involve commodity prices, but they work differently and serve different purposes.' },
          { type: 'heading', text: 'Spot Trading' },
          { type: 'paragraph', text: 'Spot commodity trading refers to buying or selling a commodity at the current market price, also known as the spot price. Settlement usually happens immediately or within a short period, depending on the market. Spot trading reflects the current value of the commodity.' },
          { type: 'heading', text: 'Futures Trading' },
          { type: 'paragraph', text: 'Futures commodity trading involves contracts to buy or sell a commodity at a predetermined price for a future date. Futures prices may be different from spot prices because they include expectations about future supply, demand, storage costs, interest rates, and market conditions.' },
          { type: 'heading', text: 'Key Differences' },
          { type: 'paragraph', text: 'Spot trading is often simpler to understand because it focuses on the current price. Futures trading is more complex because traders must consider expiry dates, contract rollover, margin requirements, and settlement rules.' },
          { type: 'paragraph', text: 'For example, spot gold shows the current market price of gold, while gold futures reflect the price of a contract for a specific future month. Similarly, spot oil and oil futures may show different prices depending on market expectations and contract timing.' },
          { type: 'heading', text: 'Which to Choose' },
          { type: 'paragraph', text: 'Futures markets are commonly used by producers, companies, and institutions to manage price risk. Spot markets may be preferred by participants who want exposure to current pricing without dealing with contract expiry. Both carry risk. The right choice depends on the trader\'s objective, experience, capital, and understanding of market structure.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Spot trading is based on the current market price, while futures trading is based on a contract price for a future date.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade spot commodities, futures, or any financial instrument. Both spot and futures trading involve risk. Prices may move rapidly and losses can be significant. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
    ]
  },

  // ── CRYPTO ─────────────────────────────────────────────────────────────────
  {
    id: 'crypto', icon: '₿', title: 'Crypto',
    desc: 'Bitcoin, Ethereum, blockchain, wallets, exchanges, leverage, liquidation, and crypto risk.',
    topics: [
      { id: 'what-is-crypto', title: 'What is Cryptocurrency?', level: 'Beginner', summary: 'A beginner-friendly introduction to digital currencies.',
        content: [
          { type: 'image', src: 'images/SNRCR001.jpg', alt: 'What is Cryptocurrency' },
          { type: 'paragraph', text: 'Cryptocurrency is a digital asset class built on cryptographic technology and distributed ledger systems. Unlike traditional fiat currencies issued by central banks, cryptocurrencies generally operate through blockchain-based networks where transactions are recorded, validated, and secured using decentralized or semi-decentralized infrastructure.' },
          { type: 'heading', text: 'What Cryptocurrency Enables' },
          { type: 'paragraph', text: 'At its core, cryptocurrency represents a new form of digital value transfer. It allows participants to send, receive, store, and trade value without always depending on traditional banking intermediaries. The most well-known cryptocurrency is Bitcoin, while Ethereum, Solana, BNB, XRP, and many others serve different purposes within the broader digital asset ecosystem.' },
          { type: 'paragraph', text: 'Cryptocurrencies may be used for payments, trading, investment, decentralized finance, smart contracts, tokenized assets, gaming ecosystems, digital identity, and blockchain-based applications. However, not all cryptocurrencies have the same utility, security, adoption, or long-term value. Some projects are backed by strong technology and active development, while others may be highly speculative or weak in fundamentals.' },
          { type: 'heading', text: 'Crypto as a Trading Asset' },
          { type: 'paragraph', text: 'From a trading perspective, cryptocurrencies are known for high volatility, 24/7 market activity, strong sentiment-driven movements, and rapid liquidity shifts. This makes the market attractive for active traders but also highly risky for beginners and over-leveraged participants.' },
          { type: 'paragraph', text: 'A professional approach to cryptocurrency requires understanding technology, market structure, liquidity, regulation, custody, exchange risk, and risk management. Traders should not view crypto only as a quick-profit market. It is a complex asset class that requires education, discipline, and careful decision-making.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Cryptocurrency is a blockchain-based digital asset class that enables value transfer, programmable finance, and decentralized market participation, but it carries significant technology, market, regulatory, and liquidity risks.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, hold, or trade any cryptocurrency or financial instrument. Cryptocurrency markets are highly volatile and may involve significant risk, including loss of capital. Conduct your own research and consult qualified professionals before making any decision.' },
        ]
      },
      { id: 'bitcoin-explained', title: 'Bitcoin Explained for Beginners', level: 'Beginner', summary: 'The origin, purpose, and mechanics of Bitcoin.',
        content: [
          { type: 'image', src: 'images/SNRCR002.jpg', alt: 'Bitcoin Explained for Beginners' },
          { type: 'paragraph', text: 'Bitcoin is the first widely adopted cryptocurrency and remains the most recognized digital asset in the global crypto market. It was designed as a decentralized peer-to-peer monetary network that allows value to be transferred without relying on banks, payment processors, or central authorities.' },
          { type: 'heading', text: 'How Bitcoin Works' },
          { type: 'paragraph', text: 'Bitcoin operates on a blockchain where transactions are grouped into blocks and validated by network participants known as miners. This system is secured through cryptography, economic incentives, and a consensus mechanism known as Proof of Work. One of Bitcoin\'s most important features is its limited supply structure, which has contributed to its reputation as "digital gold" among many market participants.' },
          { type: 'heading', text: 'Bitcoin\'s Role in the Market' },
          { type: 'paragraph', text: 'Bitcoin is not only a payment network; it is also viewed by many investors as a store of value, macro asset, liquidity indicator, and benchmark for the broader cryptocurrency market. Its price can influence market sentiment across the entire crypto ecosystem.' },
          { type: 'heading', text: 'What Moves Bitcoin\'s Price' },
          { type: 'paragraph', text: 'Bitcoin\'s value is affected by supply and demand, institutional adoption, liquidity conditions, interest rates, inflation expectations, regulation, mining economics, exchange flows, and investor sentiment. Because Bitcoin trades globally and continuously, it can react quickly to both crypto-specific and macroeconomic developments.' },
          { type: 'paragraph', text: 'For beginners, it is important to understand that Bitcoin\'s long-term reputation does not remove short-term risk. Bitcoin can move sharply in both directions and may experience deep corrections even during broader bullish cycles.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Bitcoin is a decentralized digital monetary network and crypto asset that functions as a benchmark for the digital asset market, combining scarcity, blockchain security, and global liquidity, while remaining highly volatile.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, hold, or trade Bitcoin or any financial instrument. Bitcoin is highly volatile. Past performance does not guarantee future results. Conduct your own research and consult qualified professionals before making any financial decision.' },
        ]
      },
      { id: 'ethereum-smart-contracts', title: 'Ethereum and Smart Contracts', level: 'Beginner', summary: 'How Ethereum works and what smart contracts enable.',
        content: [
          { type: 'image', src: 'images/SNRCR003.jpg', alt: 'Ethereum and Smart Contracts' },
          { type: 'paragraph', text: 'Ethereum is a blockchain platform designed to support programmable applications through smart contracts. While Bitcoin primarily focuses on decentralized value transfer, Ethereum introduced a broader infrastructure where developers can build decentralized applications, tokens, financial protocols, digital marketplaces, and blockchain-based services.' },
          { type: 'heading', text: 'Ether and the Ethereum Ecosystem' },
          { type: 'paragraph', text: 'The native asset of the Ethereum network is Ether. Ether is used to pay transaction fees, interact with applications, and support network activity. Ethereum has become one of the most important platforms in the digital asset ecosystem because many sectors, including decentralized finance, token issuance, NFTs, stablecoins, and decentralized exchanges, have been built on or inspired by its smart contract model.' },
          { type: 'heading', text: 'What is a Smart Contract' },
          { type: 'paragraph', text: 'A smart contract is a self-executing program stored on a blockchain. It automatically performs actions when specific conditions are met. For example, smart contracts can manage lending, borrowing, trading, token creation, ownership transfer, and automated settlement without requiring traditional intermediaries.' },
          { type: 'heading', text: 'Risks and Market Factors' },
          { type: 'paragraph', text: 'The professional relevance of Ethereum lies in its role as infrastructure. However, smart contracts also introduce technical risks. Poorly written code, security vulnerabilities, protocol bugs, or malicious applications can result in permanent loss of funds. Ethereum\'s market value is influenced by network usage, developer activity, transaction fees, scalability improvements, institutional adoption, competition from other blockchains, regulation, and broader crypto sentiment.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Ethereum is a programmable blockchain infrastructure that enables smart contracts and decentralized applications, making it one of the core platforms of the digital asset economy.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, hold, or trade Ethereum or any financial instrument. Smart contract ecosystems involve significant risks including price volatility, code vulnerabilities, and regulatory uncertainty. Conduct your own research and consult qualified professionals before making any decision.' },
        ]
      },
      { id: 'coins-vs-tokens', title: 'Coins vs Tokens', level: 'Beginner', summary: 'The difference between native coins and project tokens.',
        content: [
          { type: 'image', src: 'images/SNRCR004.jpg', alt: 'Coins vs Tokens' },
          { type: 'paragraph', text: 'In the cryptocurrency market, the terms "coin" and "token" are often used interchangeably, but they represent different technical and functional concepts. Understanding this distinction is essential for evaluating digital assets professionally.' },
          { type: 'heading', text: 'What is a Coin' },
          { type: 'paragraph', text: 'A coin is generally a native asset of its own blockchain. Bitcoin operates on the Bitcoin blockchain, Ether operates on Ethereum, and similar native assets support their respective networks. Coins are often used for transaction fees, network security, value transfer, staking, governance, or ecosystem participation.' },
          { type: 'heading', text: 'What is a Token' },
          { type: 'paragraph', text: 'A token is created on top of an existing blockchain infrastructure. Tokens do not usually require their own independent blockchain. Instead, they use smart contract platforms such as Ethereum or other blockchain networks to operate. Tokens may represent utility access, governance rights, stablecoin value, digital ownership, gaming assets, real-world asset claims, or protocol incentives.' },
          { type: 'heading', text: 'Why the Distinction Matters' },
          { type: 'paragraph', text: 'The distinction matters because coins and tokens can carry different risks. A coin may depend on the security and adoption of its own blockchain, while a token may depend on the underlying blockchain, the smart contract code, issuer credibility, liquidity, and project fundamentals.' },
          { type: 'paragraph', text: 'Professionally, traders and investors should not evaluate a digital asset only by price movement. They should understand whether the asset is a native coin, utility token, governance token, stablecoin, security-like token, or speculative asset. Each category has different risk, valuation logic, and regulatory considerations.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Coins are native assets of independent blockchains, while tokens are digital assets issued on existing blockchain infrastructure, often serving specific roles within applications or ecosystems.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, hold, or trade any coin, token, or financial instrument. Digital assets may involve high volatility, low liquidity, smart contract vulnerabilities, and regulatory uncertainty. Conduct your own research and consult qualified professionals before making any decision.' },
        ]
      },
      { id: 'what-is-blockchain', title: 'What is Blockchain?', level: 'Beginner', summary: 'The technology underpinning all cryptocurrencies.',
        content: [
          { type: 'image', src: 'images/SNRCR005.jpg', alt: 'What is Blockchain' },
          { type: 'paragraph', text: 'Blockchain is a distributed digital ledger technology that records transactions in a structured, transparent, and tamper-resistant manner. It is the foundational technology behind many cryptocurrencies and decentralized applications.' },
          { type: 'heading', text: 'How Blockchain Works' },
          { type: 'paragraph', text: 'A blockchain stores data in blocks that are linked together in chronological order. Each block contains transaction information and is connected to the previous block through cryptographic methods. Once data is confirmed on the network, changing it becomes extremely difficult without broad network agreement.' },
          { type: 'heading', text: 'Why Blockchain Matters' },
          { type: 'paragraph', text: 'The major value of blockchain lies in trust reduction. Traditional systems often depend on central authorities to maintain records, verify ownership, and process transactions. Blockchain allows multiple participants to verify the same ledger independently, reducing reliance on a single intermediary.' },
          { type: 'heading', text: 'Types of Blockchain' },
          { type: 'paragraph', text: 'Blockchains may be public, private, permissioned, or permissionless. Public blockchains such as Bitcoin and Ethereum allow open participation, while private or permissioned blockchains may be used by institutions for controlled environments. Blockchain technology can support digital currencies, smart contracts, tokenization, supply chain tracking, digital identity, and decentralized finance.' },
          { type: 'paragraph', text: 'For traders and investors, understanding blockchain helps in evaluating whether a crypto project has genuine technological value or is mainly driven by speculation.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Blockchain is a distributed ledger system that enables transparent, verifiable, and tamper-resistant digital recordkeeping without depending entirely on a central authority.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to use, buy, sell, or trade any cryptocurrency or financial instrument. Blockchain-based systems may involve technology risk, cybersecurity threats, smart contract vulnerabilities, and regulatory uncertainty. Conduct your own research and consult qualified professionals where required.' },
        ]
      },
      { id: 'cex-vs-dex', title: 'Centralized vs Decentralized Exchanges', level: 'Beginner', summary: 'Understanding CEX and DEX trading platforms.',
        content: [
          { type: 'image', src: 'images/SNRCR006.jpg', alt: 'Centralized vs Decentralized Exchanges' },
          { type: 'paragraph', text: 'Cryptocurrency exchanges are platforms that allow users to buy, sell, and trade digital assets. The two major categories are centralized exchanges and decentralized exchanges, each with a different structure, risk profile, and user experience.' },
          { type: 'heading', text: 'Centralized Exchanges (CEX)' },
          { type: 'paragraph', text: 'A centralized exchange, commonly called a CEX, is operated by a company or organization. Users create accounts, deposit funds, and trade through the exchange\'s internal order book or trading system. Centralized exchanges often provide high liquidity, fast execution, fiat currency support, customer service, advanced order types, and professional trading interfaces. The main limitation is custody risk — deposited funds are controlled by the exchange, creating exposure to failure, hacking, insolvency, or regulatory action.' },
          { type: 'heading', text: 'Decentralized Exchanges (DEX)' },
          { type: 'paragraph', text: 'A decentralized exchange, commonly called a DEX, allows users to trade directly through blockchain wallets and smart contracts. Users generally retain control of their private keys and assets. DEX platforms support self-custody and decentralized access, but they also require more technical understanding.' },
          { type: 'heading', text: 'DEX Risks' },
          { type: 'paragraph', text: 'DEX trading carries risks such as smart contract vulnerabilities, wallet compromise, slippage, low liquidity, fake tokens, front-running, and irreversible transactions. Unlike centralized platforms, decentralized exchanges may not offer customer support or recovery options.' },
          { type: 'paragraph', text: 'Professional crypto participants evaluate exchanges based on custody, liquidity, fees, execution quality, asset availability, security, regulation, transparency, and counterparty risk.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Centralized exchanges offer convenience and liquidity through company-operated platforms, while decentralized exchanges provide wallet-based trading through smart contracts with greater self-custody responsibility.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to use any exchange or trade any financial instrument. Both CEX and DEX involve risks including hacking, smart contract vulnerabilities, and permanent loss of funds. Conduct your own research and consult qualified professionals where required.' },
        ]
      },
      { id: 'spot-vs-futures-crypto', title: 'Spot vs Futures Trading in Crypto', level: 'Intermediate', summary: 'Key differences and which suits your risk profile.',
        content: [
          { type: 'image', src: 'images/SNRCR007.jpg', alt: 'Spot vs Futures Trading in Crypto' },
          { type: 'paragraph', text: 'Spot and futures trading are two major methods of participating in cryptocurrency markets. Although both are based on crypto price movement, they differ significantly in ownership, risk, cost, and complexity.' },
          { type: 'heading', text: 'Spot Trading' },
          { type: 'paragraph', text: 'Spot trading involves buying or selling the actual cryptocurrency at the current market price. When a trader buys Bitcoin or Ethereum in the spot market, they own that asset directly within an exchange account or wallet. Spot trading is generally more straightforward and does not involve liquidation risk unless borrowed funds or margin products are used.' },
          { type: 'heading', text: 'Futures Trading' },
          { type: 'paragraph', text: 'Futures trading involves contracts that allow traders to speculate on the future price movement of a cryptocurrency without necessarily owning the underlying asset. Futures traders can open long positions when expecting prices to rise or short positions when expecting prices to fall. Many crypto futures products also allow leverage, which increases both potential reward and risk.' },
          { type: 'heading', text: 'Key Differences in Exposure' },
          { type: 'paragraph', text: 'Spot traders are exposed mainly to market price movement and custody risk. Futures traders are exposed to price movement, leverage, margin requirements, funding fees, liquidation risk, and contract-specific mechanics. Futures trading requires a deeper understanding of market structure, funding rates, margin ratios, volatility, and risk control.' },
          { type: 'paragraph', text: 'For beginners, spot trading is generally easier to understand, while futures trading should be approached only after proper education and practice.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Spot trading provides direct ownership of crypto assets, while futures trading provides contract-based exposure with additional leverage, margin, and liquidation risk.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any cryptocurrency or financial instrument. Crypto spot and futures trading involve significant risk including liquidation, leverage losses, and exchange risk. Conduct your own research and consult qualified professionals before making any decision.' },
        ]
      },
      { id: 'leverage-crypto', title: 'Leverage in Crypto Trading', level: 'Intermediate', summary: 'How leverage amplifies both gains and losses in crypto.',
        content: [
          { type: 'image', src: 'images/SNRCR008.jpg', alt: 'Leverage in Crypto Trading' },
          { type: 'paragraph', text: 'Leverage in crypto trading allows traders to control a larger position than their actual capital contribution. For example, with 10x leverage, a trader can control a position ten times larger than the margin used. This increases market exposure, which can magnify both profits and losses.' },
          { type: 'heading', text: 'The Danger of Leverage' },
          { type: 'paragraph', text: 'Leverage is common in crypto futures and margin trading. While it can be useful for experienced traders, it is one of the most dangerous tools for beginners. Crypto markets are already highly volatile, and leverage reduces the margin of error. A small adverse price movement can create a large loss relative to the trader\'s deposited margin.' },
          { type: 'heading', text: 'How Professionals Use Leverage' },
          { type: 'paragraph', text: 'Professional traders do not use leverage simply to increase profits. They use it carefully as part of a defined risk model. The most important considerations include position size, stop-loss placement, liquidation price, margin mode, volatility, funding fees, and maximum account risk per trade.' },
          { type: 'heading', text: 'Key Principles' },
          { type: 'paragraph', text: 'High leverage can create the illusion of opportunity, but it often leads to emotional trading, forced liquidation, and account damage. Lower leverage combined with disciplined position sizing is usually more sustainable than aggressive exposure. A trader should always understand the difference between isolated margin and cross margin, know the liquidation level before entering the trade, and avoid using leverage during highly volatile news events without proper planning.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Leverage is a risk-amplifying tool that increases market exposure beyond deposited capital and must be managed through strict position sizing, margin control, and predefined risk limits.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to use leverage or trade any financial instrument. Leveraged crypto trading is extremely risky and may result in rapid or total loss of capital. Conduct your own research, apply strict risk management, and consult qualified professionals before making any financial decision.' },
        ]
      },
      { id: 'liquidation-crypto', title: 'Liquidation in Crypto Futures', level: 'Intermediate', summary: 'What liquidation means and how to avoid it.',
        content: [
          { type: 'image', src: 'images/SNRCR009.jpg', alt: 'Liquidation in Crypto Futures' },
          { type: 'paragraph', text: 'Liquidation in crypto futures occurs when a trader\'s margin is no longer sufficient to support an open leveraged position. When the position moves too far against the trader, the exchange automatically closes it to prevent further losses beyond the required margin threshold.' },
          { type: 'heading', text: 'Why Liquidation Happens' },
          { type: 'paragraph', text: 'Liquidation is directly related to leverage, position size, maintenance margin, and market volatility. The higher the leverage, the closer the liquidation price usually is to the entry price. This means that even a small unfavorable price movement can result in forced closure of the trade.' },
          { type: 'heading', text: 'Long and Short Liquidation' },
          { type: 'paragraph', text: 'Liquidation can occur in both long and short positions. A long position may be liquidated if the price falls significantly, while a short position may be liquidated if the price rises significantly. During high volatility, liquidation can occur very quickly, sometimes before a trader has time to react.' },
          { type: 'heading', text: 'How to Reduce Liquidation Risk' },
          { type: 'paragraph', text: 'Professional traders monitor liquidation price before entering any futures trade. They also understand that liquidation is not only a price level but a risk management failure if not planned properly. Stop-loss orders, lower leverage, smaller position sizing, and isolated margin can help reduce liquidation risk. Liquidation may also be affected by funding fees, maintenance margin changes, exchange calculations, and sudden liquidity gaps.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Liquidation is the forced closure of a leveraged futures position when account margin falls below the required maintenance threshold.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade crypto futures or use leverage. Crypto futures trading involves high risk, and liquidation may result in the loss of part or all of the margin allocated. Conduct your own research and consult qualified professionals before making any financial decision.' },
        ]
      },
      { id: 'crypto-wallets', title: 'Crypto Wallets: Hot vs Cold', level: 'Beginner', summary: 'Keeping your crypto safe — online vs offline storage.',
        content: [
          { type: 'image', src: 'images/SNRCR010.jpg', alt: 'Crypto Wallets Hot vs Cold' },
          { type: 'paragraph', text: 'A crypto wallet is a tool that allows users to access, manage, send, and receive digital assets on a blockchain. Contrary to common misunderstanding, a wallet does not physically store cryptocurrency. Instead, it stores or manages private keys that control access to blockchain-based assets.' },
          { type: 'heading', text: 'Hot Wallets' },
          { type: 'paragraph', text: 'A hot wallet is connected to the internet. Examples include mobile wallets, browser wallets, desktop wallets, and exchange-based wallets. Hot wallets are convenient for active trading, frequent transfers, decentralized applications, and daily use. However, because they are online, they are more exposed to hacking, phishing attacks, malware, malicious links, and device compromise.' },
          { type: 'heading', text: 'Cold Wallets' },
          { type: 'paragraph', text: 'A cold wallet is kept offline. Examples include hardware wallets and offline storage methods. Cold wallets are generally preferred for long-term storage because they reduce exposure to online threats. However, they require strong personal responsibility. If the recovery phrase is lost, stolen, or exposed, funds may be permanently lost.' },
          { type: 'heading', text: 'Private Key Control' },
          { type: 'paragraph', text: 'The central principle of wallet security is private key control. Whoever controls the private key or recovery phrase controls the assets. This is why the phrase "not your keys, not your coins" is commonly used in the crypto industry. Professional crypto asset management requires a clear custody strategy — active trading funds, long-term holdings, and operational wallets should ideally be separated based on purpose and risk.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Crypto wallets are private key management tools that provide access to digital assets, with hot wallets prioritizing convenience and cold wallets prioritizing security.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or cybersecurity advice. Crypto wallet use involves serious risks including private key loss, phishing, hacking, and permanent loss of funds. Users are fully responsible for securing their own assets. Conduct your own research and consult qualified professionals where required.' },
        ]
      },
      { id: 'stablecoins', title: 'Stablecoins: USDT, USDC and Their Role', level: 'Beginner', summary: 'How stablecoins work and why traders use them.',
        content: [
          { type: 'image', src: 'images/SNRCR011.jpg', alt: 'Stablecoins USDT USDC and Their Role' },
          { type: 'paragraph', text: 'Stablecoins are digital assets designed to maintain a relatively stable value, usually by referencing a traditional currency such as the US Dollar. USDT and USDC are among the most widely used dollar-linked stablecoins in the cryptocurrency market.' },
          { type: 'heading', text: 'Role in the Crypto Market' },
          { type: 'paragraph', text: 'Stablecoins play a critical role in crypto market infrastructure. They allow traders to move value between exchanges, quote trading pairs, preserve capital during volatility, access liquidity, participate in decentralized finance, and settle transactions without constantly converting back to traditional bank currency.' },
          { type: 'heading', text: 'How Traders Use Stablecoins' },
          { type: 'paragraph', text: 'For active traders, stablecoins serve as a base currency for market participation. A trader may sell Bitcoin into USDT or USDC to reduce exposure while keeping funds available for future opportunities. Many crypto exchanges use stablecoin pairs as primary trading markets.' },
          { type: 'heading', text: 'Stablecoin Risks' },
          { type: 'paragraph', text: 'Stablecoins are not the same as bank deposits and they are not risk-free. Their stability depends on reserve quality, issuer credibility, redemption mechanisms, market confidence, regulatory treatment, liquidity, and blockchain infrastructure. A stablecoin can temporarily or permanently lose its peg under stress conditions. USDT, USDC, and other stablecoins may differ in reserve structure, transparency, liquidity, and regulatory approach.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Stablecoins are blockchain-based value instruments designed to track stable reference assets, serving as liquidity, settlement, and trading infrastructure within the digital asset market.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to use, buy, sell, or hold any stablecoin or financial instrument. Stablecoins involve risks including de-pegging, reserve uncertainty, and regulatory action. Stable value is not guaranteed under all market conditions. Conduct your own research and consult qualified professionals before making any decision.' },
        ]
      },
      { id: 'market-sentiment-crypto', title: 'Market Sentiment in Crypto', level: 'Intermediate', summary: 'How crowd psychology drives crypto price cycles.',
        content: [
          { type: 'image', src: 'images/SNRCR012.jpg', alt: 'Market Sentiment in Crypto' },
          { type: 'paragraph', text: 'Market sentiment refers to the collective psychology, confidence, and emotional positioning of traders and investors in the cryptocurrency market. Because crypto markets are highly speculative, sentiment can have a major impact on short-term and medium-term price movement.' },
          { type: 'heading', text: 'Positive and Negative Sentiment' },
          { type: 'paragraph', text: 'Positive sentiment may appear during rising prices, strong volume, institutional interest, bullish news, favorable regulation, ecosystem growth, or broad market optimism. Negative sentiment may appear during sharp sell-offs, exchange failures, regulatory pressure, hacks, macroeconomic uncertainty, or liquidation events.' },
          { type: 'paragraph', text: 'Crypto sentiment can change faster than traditional markets because digital assets trade 24/7 and are heavily influenced by social media, news flow, leverage, liquidity, and crowd behavior. This creates rapid cycles of fear, greed, panic, and euphoria.' },
          { type: 'heading', text: 'How Professionals Read Sentiment' },
          { type: 'paragraph', text: 'Professional traders study sentiment as part of market context. They may observe funding rates, open interest, liquidation data, trading volume, social activity, exchange inflows and outflows, volatility, and sentiment indexes. However, sentiment should not be used alone as a trading signal. Extreme optimism may indicate overheating, but markets can remain bullish longer than expected. Extreme fear may indicate opportunity, but prices can continue falling.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Crypto market sentiment measures the psychological condition of market participants and helps traders understand whether price movement is being driven by confidence, fear, speculation, or risk appetite.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any cryptocurrency or financial instrument. Crypto sentiment can change rapidly and sentiment indicators do not guarantee future price movement. Conduct your own research and consult qualified professionals before making any decision.' },
        ]
      },
      { id: 'fear-greed-index', title: 'Fear and Greed Index Explained', level: 'Beginner', summary: 'Using sentiment indicators to time market entries.',
        content: [
          { type: 'image', src: 'images/SNRCR013.jpg', alt: 'Fear and Greed Index Explained' },
          { type: 'paragraph', text: 'The Fear and Greed Index is a sentiment indicator designed to measure the emotional condition of the cryptocurrency market. It attempts to show whether market participants are acting with excessive fear, caution, confidence, or greed.' },
          { type: 'heading', text: 'How Fear and Greed Affect Markets' },
          { type: 'paragraph', text: 'In crypto markets, sentiment can influence price movement significantly. During periods of extreme fear, traders may sell aggressively, avoid risk, or exit positions due to panic. During periods of extreme greed, traders may become overly confident, chase rising prices, increase leverage, and ignore risk.' },
          { type: 'heading', text: 'How to Use the Index' },
          { type: 'paragraph', text: 'The index is useful because it provides a simplified view of market psychology. However, professional traders do not treat it as a direct buy or sell signal. Instead, they use it as a supporting tool to understand whether market conditions may be emotionally stretched. Extreme fear can sometimes appear near market bottoms, but it can also continue during strong downtrends. Extreme greed can sometimes appear near market tops, but it can also persist during powerful bullish trends.' },
          { type: 'paragraph', text: 'The real value of the Fear and Greed Index is not prediction. Its value is awareness. It helps traders avoid emotional decision-making by showing when the market may be driven more by psychology than by balanced analysis.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> The Fear and Greed Index is a market sentiment tool that helps assess emotional extremes in crypto, but it should only be used as part of a broader analytical framework.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any cryptocurrency or financial instrument. The Fear and Greed Index does not guarantee future market direction. Crypto markets can remain in extreme fear or greed for extended periods. Conduct your own research and consult qualified professionals before making any decision.' },
        ]
      },
      { id: 'crypto-risk-management', title: 'Crypto Risk Management for Beginners', level: 'Beginner', summary: 'Protecting your capital in the volatile crypto market.',
        content: [
          { type: 'image', src: 'images/SNRCR014.jpg', alt: 'Crypto Risk Management for Beginners' },
          { type: 'paragraph', text: 'Risk management is the foundation of sustainable cryptocurrency trading. In a market known for volatility, leverage, rapid sentiment shifts, and 24/7 price movement, protecting capital is more important than finding profitable entries.' },
          { type: 'heading', text: 'Capital Preservation' },
          { type: 'paragraph', text: 'The first principle of crypto risk management is capital preservation. A trader should never risk an amount that could seriously damage their financial position or emotional discipline. Every trade should be planned with a defined risk amount, entry level, invalidation point, and exit strategy.' },
          { type: 'heading', text: 'Position Sizing' },
          { type: 'paragraph', text: 'Position sizing is one of the most important risk management tools. Even a strong trading idea can become dangerous if the position size is too large. Beginners often lose money not because their analysis is always wrong, but because their risk per trade is uncontrolled.' },
          { type: 'heading', text: 'Stop-Loss Planning' },
          { type: 'paragraph', text: 'A stop-loss should be based on market structure and risk tolerance, not fear or hope. Moving a stop-loss emotionally after the trade moves against the position is a common mistake. Leverage must be handled with extreme caution. High leverage can quickly turn small price movements into large account losses.' },
          { type: 'heading', text: 'Broader Risk Factors' },
          { type: 'paragraph', text: 'Crypto risk management also includes exchange selection, wallet security, avoiding suspicious projects, understanding liquidity, managing emotional behavior, and not concentrating all capital into one asset or trade. Professional traders understand that survival comes before profit. A trader who protects capital remains available for future opportunities.' },
          { type: 'callout', text: '<strong>In professional terms:</strong> Crypto risk management is the disciplined process of controlling exposure, protecting capital, managing leverage, securing assets, and making decisions based on structured planning rather than emotion.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any cryptocurrency or financial instrument. Cryptocurrency trading involves significant risk including market volatility, leverage losses, liquidation, and possible total loss of capital. Risk management may reduce risk but cannot eliminate it or guarantee profit. Conduct your own research and consult qualified professionals before making any decision.' },
        ]
      },
    ]
  },

  // ── FOREX ──────────────────────────────────────────────────────────────────
  {
    id: 'forex', icon: '💱', title: 'Forex',
    desc: 'Currency pairs, pips, spread, lot size, margin, leverage, and economic calendar.',
    topics: [
      { id: 'what-is-forex', title: 'What is Forex Trading?', level: 'Beginner', summary: 'An introduction to the world\'s largest financial market.',
        content: [
          { type: 'image', src: 'images/SNRFX001.jpg', alt: 'What is Forex Trading' },
          { type: 'paragraph', text: 'Forex trading, also known as foreign exchange trading or currency trading, is the process of buying one currency and selling another currency at the same time. The forex market is the largest and most actively traded financial market in the world, where currencies such as the US Dollar, Euro, British Pound, Japanese Yen, Swiss Franc, and other global currencies are exchanged.' },
          { type: 'heading', text: 'How Forex Trading Works' },
          { type: 'paragraph', text: 'The main purpose of forex trading is to benefit from changes in currency prices. Currency values move due to many factors, including interest rates, inflation, economic data, central bank decisions, political events, global trade, and market sentiment. For example, if a trader believes the Euro will strengthen against the US Dollar, they may buy EUR/USD. If the Euro rises against the Dollar, the trader may make a profit. If the price moves against the trade, the trader may face a loss.' },
          { type: 'heading', text: 'Currency Pairs' },
          { type: 'paragraph', text: 'Forex is traded in currency pairs. This means one currency is compared against another. Some common examples include EUR/USD, GBP/USD, USD/JPY, and USD/CHF. The first currency in the pair is called the base currency, while the second currency is called the quote currency.' },
          { type: 'heading', text: 'Why Forex is Popular' },
          { type: 'paragraph', text: 'Forex trading is popular because the market is highly liquid, available almost 24 hours a day during weekdays, and provides opportunities in both rising and falling markets. However, it is also a highly risky market, especially when leverage is used. Small price movements can create significant gains or losses.' },
          { type: 'heading', text: 'What Forex Trading Requires' },
          { type: 'paragraph', text: 'Successful forex trading requires knowledge, discipline, risk management, and a clear understanding of market behavior. Traders should not treat forex as a quick-money opportunity. Instead, it should be approached as a professional financial skill that requires continuous learning, patience, and proper strategy.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Forex trading is the buying and selling of currencies with the aim of benefiting from changes in exchange rates.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any currency or financial instrument. Forex trading involves significant risk. The use of leverage can magnify both profits and losses, and traders may lose part or all of their invested capital. Past performance does not guarantee future results. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'currency-pairs', title: 'Major, Minor, and Exotic Pairs', level: 'Beginner', summary: 'Understanding the different categories of currency pairs.',
        content: [
          { type: 'image', src: 'images/SNRFX002.jpg', alt: 'Major Minor and Exotic Pairs' },
          { type: 'paragraph', text: 'In forex trading, currencies are traded in pairs. These currency pairs are generally divided into three main categories: major pairs, minor pairs, and exotic pairs. Understanding these categories helps traders identify market liquidity, volatility, trading cost, and overall risk level.' },
          { type: 'heading', text: 'Major Currency Pairs' },
          { type: 'paragraph', text: 'Major currency pairs include the most actively traded currencies in the world and always involve the US Dollar. Examples include EUR/USD, GBP/USD, USD/JPY, USD/CHF, AUD/USD, USD/CAD, and NZD/USD. These pairs usually have high liquidity, tighter spreads, and more stable price movement. Because of this, major pairs are commonly preferred by beginner and professional traders.' },
          { type: 'heading', text: 'Minor Currency Pairs' },
          { type: 'paragraph', text: 'Minor currency pairs, also known as cross currency pairs, do not include the US Dollar but involve major global currencies. Examples include EUR/GBP, EUR/JPY, GBP/JPY, AUD/JPY, and EUR/AUD. These pairs can offer strong trading opportunities, but they may have wider spreads and more volatility than major pairs.' },
          { type: 'heading', text: 'Exotic Currency Pairs' },
          { type: 'paragraph', text: 'Exotic currency pairs include one major currency and one currency from an emerging or smaller economy. Examples may include USD/TRY, USD/ZAR, USD/MXN, EUR/TRY, and USD/SGD. Exotic pairs usually have lower liquidity, wider spreads, and higher volatility. They can move sharply due to political events, economic instability, inflation, or lower market participation.' },
          { type: 'heading', text: 'Choosing the Right Pair' },
          { type: 'paragraph', text: 'The choice between major, minor, and exotic pairs depends on the trader\'s experience, strategy, risk tolerance, and market understanding. Major pairs are generally more suitable for learning and structured trading, while exotic pairs require more caution due to unpredictable price behavior and higher transaction costs. Professional traders study volatility, spread, session timing, economic news, and technical structure before entering a trade.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Major pairs are the most liquid and popular, minor pairs exclude the US Dollar, and exotic pairs involve emerging market currencies with higher risk and volatility.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any currency or financial instrument. Currency pairs can behave differently based on liquidity, volatility, and economic conditions. The use of leverage can magnify both profits and losses. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'base-quote-currency', title: 'Base Currency and Quote Currency', level: 'Beginner', summary: 'How currency pair pricing works.',
        content: [
          { type: 'image', src: 'images/SNRFX003.jpg', alt: 'Base Currency and Quote Currency' },
          { type: 'paragraph', text: 'In forex trading, every currency pair consists of two currencies: the base currency and the quote currency. Understanding this concept is essential because it explains how currency prices are read and how profit or loss is calculated.' },
          { type: 'heading', text: 'Base and Quote Explained' },
          { type: 'paragraph', text: 'The base currency is the first currency shown in a currency pair. The quote currency is the second currency shown in the pair. For example, in EUR/USD, EUR is the base currency and USD is the quote currency. If EUR/USD is trading at 1.1000, it means 1 Euro is equal to 1.1000 US Dollars.' },
          { type: 'heading', text: 'Reading the Price' },
          { type: 'paragraph', text: 'The price of a forex pair shows how much of the quote currency is needed to buy one unit of the base currency. When the price of EUR/USD rises, it means the Euro is becoming stronger against the US Dollar. When the price falls, it means the Euro is weakening against the US Dollar.' },
          { type: 'heading', text: 'Buying and Selling' },
          { type: 'paragraph', text: 'If a trader buys a currency pair, they are buying the base currency and selling the quote currency. If a trader sells a currency pair, they are selling the base currency and buying the quote currency. This is why forex trading always involves two currencies at the same time.' },
          { type: 'paragraph', text: 'For example, if a trader buys GBP/USD, they expect the British Pound to strengthen against the US Dollar. If the price moves upward, the trade may become profitable. If the price moves downward, the trade may result in a loss.' },
          { type: 'callout', text: '<strong>In simple words:</strong> The base currency is the first currency in a pair, and the quote currency is the second. The price tells how much of the quote currency is needed to buy one unit of the base currency.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any currency or financial instrument. Exchange rates can move quickly due to economic data, interest rates, and geopolitical events. The use of leverage can magnify both profits and losses. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'what-are-pips', title: 'What are Pips in Forex?', level: 'Beginner', summary: 'Understanding pip values and how to calculate them.',
        content: [
          { type: 'image', src: 'images/SNRFX004.jpg', alt: 'What are Pips in Forex' },
          { type: 'paragraph', text: 'A pip is one of the most important measurement units in forex trading. It is used to measure the movement in the price of a currency pair. The word "pip" commonly refers to "percentage in point" or "price interest point."' },
          { type: 'heading', text: 'How Pips are Measured' },
          { type: 'paragraph', text: 'In most currency pairs, one pip is equal to the fourth decimal place. For example, if EUR/USD moves from 1.1000 to 1.1001, this movement is equal to 1 pip. If the price moves from 1.1000 to 1.1050, the movement is 50 pips.' },
          { type: 'paragraph', text: 'For Japanese Yen pairs, such as USD/JPY or EUR/JPY, one pip is usually measured at the second decimal place. For example, if USD/JPY moves from 150.00 to 150.01, that movement is equal to 1 pip.' },
          { type: 'heading', text: 'Why Pips Matter' },
          { type: 'paragraph', text: 'Pips help traders calculate profit, loss, risk, and reward. Instead of saying that EUR/USD moved from 1.1000 to 1.1050, traders usually say the pair moved 50 pips. This makes it easier to discuss price movement across different forex pairs.' },
          { type: 'paragraph', text: 'The value of a pip depends on the currency pair, lot size, and account currency. This is why traders must understand position sizing before entering a trade.' },
          { type: 'heading', text: 'Pips in Risk Management' },
          { type: 'paragraph', text: 'Pips are also important for setting stop-loss and take-profit levels. A trader may risk 30 pips to target 60 pips, creating a risk-reward ratio of 1:2. This helps traders plan trades professionally instead of entering the market emotionally.' },
          { type: 'callout', text: '<strong>In simple words:</strong> A pip is a small unit used to measure price movement in forex. It helps traders calculate profit, loss, stop-loss, and target levels.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any currency or financial instrument. Pip value, profit, and loss may vary depending on the broker, account type, lot size, and leverage. The use of leverage can magnify both profits and losses. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'what-is-spread', title: 'What is Spread in Forex?', level: 'Beginner', summary: 'How brokers make money and how spread affects your trades.',
        content: [
          { type: 'image', src: 'images/SNRFX005.jpg', alt: 'What is Spread in Forex' },
          { type: 'paragraph', text: 'Spread is the difference between the buying price and the selling price of a currency pair. In forex trading, every currency pair has two prices: the bid price and the ask price.' },
          { type: 'heading', text: 'Bid and Ask Price' },
          { type: 'paragraph', text: 'The bid price is the price at which a trader can sell a currency pair. The ask price is the price at which a trader can buy a currency pair. The difference between these two prices is called the spread.' },
          { type: 'paragraph', text: 'For example, if EUR/USD has a bid price of 1.1000 and an ask price of 1.1002, the spread is 2 pips. This means the trader enters the market with a small cost already included. The trade usually needs to move in the trader\'s favor by at least the spread amount before it reaches breakeven.' },
          { type: 'heading', text: 'Spread as a Trading Cost' },
          { type: 'paragraph', text: 'Spread is one of the main trading costs in forex. Lower spreads are generally better for traders, especially for short-term strategies such as scalping or intraday trading. Wider spreads can make trading more expensive and can reduce profitability.' },
          { type: 'heading', text: 'What Affects the Spread' },
          { type: 'paragraph', text: 'Spreads are affected by liquidity, volatility, market session, currency pair, broker pricing, and economic news. Major pairs such as EUR/USD usually have lower spreads because they are highly liquid. Exotic pairs often have wider spreads because they are less liquid and riskier.' },
          { type: 'paragraph', text: 'During major news events, spreads can widen quickly. This can cause unexpected entry prices, higher trading costs, or increased slippage. Professional traders always check the spread before placing a trade, especially during volatile market conditions.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Spread is the difference between the buy price and sell price. It is one of the basic costs of forex trading.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any currency or financial instrument. Spreads may change due to market volatility, liquidity, and news events. Trading costs can affect profitability. The use of leverage can magnify both profits and losses. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'lot-margin-leverage', title: 'Lot Size, Margin, and Leverage', level: 'Intermediate', summary: 'The three pillars of forex position sizing.',
        content: [
          { type: 'image', src: 'images/SNRFX006.jpg', alt: 'Lot Size Margin and Leverage' },
          { type: 'paragraph', text: 'Lot size, margin, and leverage are three important concepts in forex trading. These concepts directly affect trade size, risk exposure, profit potential, and possible loss.' },
          { type: 'heading', text: 'Lot Size' },
          { type: 'paragraph', text: 'A lot size represents the size of a forex trade. In general, forex trading uses standard lots, mini lots, micro lots, and sometimes nano lots depending on the broker. A standard lot usually represents 100,000 units of the base currency. A mini lot represents 10,000 units, and a micro lot represents 1,000 units. The larger the lot size, the greater the value of each pip movement.' },
          { type: 'heading', text: 'Margin' },
          { type: 'paragraph', text: 'Margin is the amount of money required to open and maintain a leveraged trade. It is not a fee, but a portion of account funds set aside by the broker as security for the position. If a trader opens a larger position, more margin is usually required.' },
          { type: 'heading', text: 'Leverage' },
          { type: 'paragraph', text: 'Leverage allows traders to control a larger position with a smaller amount of capital. For example, leverage of 1:100 means a trader can control a position much larger than the actual margin deposited. While leverage can increase profit potential, it also increases risk. A small market movement against the trade can result in a significant loss.' },
          { type: 'heading', text: 'Managing All Three Together' },
          { type: 'paragraph', text: 'Many beginner traders focus only on profit potential and ignore the danger of over-leverage. This is one of the most common mistakes in forex trading. Professional traders calculate position size carefully and decide risk before entering the market.' },
          { type: 'paragraph', text: 'Lot size, margin, and leverage should always be managed together. A trader must understand how much capital is at risk, how much margin is being used, and how much a pip movement can affect the account balance.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Lot size controls trade volume, margin is the required security amount, and leverage allows traders to control larger positions with smaller capital. Together, they define the real risk of a forex trade.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any currency or financial instrument. Forex trading with margin and leverage involves a high level of risk. Leverage can magnify both profits and losses, and losses may occur quickly in volatile conditions. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'fa-forex', title: 'Fundamental Analysis in Forex', level: 'Intermediate', summary: 'Using economic data and news to trade currencies.',
        content: [
          { type: 'image', src: 'images/SNRFX007.jpg', alt: 'Fundamental Analysis in Forex' },
          { type: 'paragraph', text: 'Fundamental analysis in forex focuses on understanding the economic, financial, and political factors that influence currency values. Unlike technical analysis, which studies price charts and patterns, fundamental analysis looks at the reasons behind currency movement.' },
          { type: 'heading', text: 'What Drives Currency Values' },
          { type: 'paragraph', text: 'Currencies are strongly affected by the economic strength of their countries. When an economy is growing, inflation is controlled, employment is strong, and interest rates are attractive, the currency may become stronger. When an economy is weak, inflation is unstable, or political uncertainty is high, the currency may lose value.' },
          { type: 'heading', text: 'Key Fundamental Factors' },
          { type: 'paragraph', text: 'Some of the most important factors in forex fundamental analysis include interest rates, inflation data, employment reports, gross domestic product, central bank policy, trade balance, consumer confidence, and geopolitical events. Central banks play a major role because their decisions on interest rates and monetary policy can create strong movements in currency markets.' },
          { type: 'paragraph', text: 'For example, if a central bank raises interest rates, its currency may strengthen because higher rates can attract investors looking for better returns. On the other hand, if a central bank signals rate cuts or economic weakness, the currency may weaken.' },
          { type: 'heading', text: 'How to Use Fundamental Analysis' },
          { type: 'paragraph', text: 'Fundamental analysis helps traders understand the bigger market picture. It can explain why a currency is trending strongly, why volatility is increasing, or why the market is reacting sharply to news. This approach is especially useful for swing traders, position traders, and investors who want to understand long-term currency direction.' },
          { type: 'paragraph', text: 'However, fundamental analysis is not always simple. Markets may react differently than expected because future expectations are often already priced in. Sometimes, good news may still cause a currency to fall if traders expected even better results.' },
          { type: 'heading', text: 'Combining with Technical Analysis' },
          { type: 'paragraph', text: 'Professional traders often combine fundamental analysis with technical analysis. Fundamentals help explain the reason behind market movement, while technical analysis helps identify entry points, exit points, and risk levels.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Fundamental analysis in forex studies economic data, central bank decisions, and global events to understand why currencies move.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any currency or financial instrument. Forex markets can react unpredictably to economic data and global events. Fundamental analysis does not guarantee accurate predictions or profitable results. The use of leverage can magnify both profits and losses. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
      { id: 'economic-calendar', title: 'Economic Calendar and News Trading', level: 'Intermediate', summary: 'How to use the economic calendar to anticipate market moves.',
        content: [
          { type: 'image', src: 'images/SNRFX008.jpg', alt: 'Economic Calendar and News Trading' },
          { type: 'paragraph', text: 'An economic calendar is an important tool used by forex traders to track upcoming financial events, economic data releases, and central bank announcements. These events can create strong movement in currency markets and may significantly affect trading conditions.' },
          { type: 'heading', text: 'What the Economic Calendar Includes' },
          { type: 'paragraph', text: 'The economic calendar usually includes events such as interest rate decisions, inflation reports, employment data, GDP announcements, retail sales, manufacturing data, consumer confidence reports, and central bank speeches. Each event normally shows the expected result, previous result, and actual result once released.' },
          { type: 'heading', text: 'News Trading' },
          { type: 'paragraph', text: 'News trading is a trading approach where traders make decisions based on economic news and market reaction. Some traders enter trades before the news based on expectations, while others wait for the news release and then trade the market reaction. Both approaches involve risk.' },
          { type: 'heading', text: 'Impact of High-Impact News' },
          { type: 'paragraph', text: 'High-impact news can cause rapid price movements, wider spreads, slippage, and increased volatility. For example, events such as US Non-Farm Payrolls, Federal Reserve interest rate decisions, inflation data, or major central bank speeches can move forex pairs sharply within seconds or minutes.' },
          { type: 'heading', text: 'Using the Calendar for Risk Management' },
          { type: 'paragraph', text: 'Professional traders use the economic calendar not only to find trading opportunities but also to manage risk. Even traders who do not trade news directly should be aware of upcoming high-impact events because open positions can be affected by sudden market movements.' },
          { type: 'paragraph', text: 'News trading requires discipline, speed, and strong risk control. It is not suitable for every trader, especially beginners. Market reaction can be unpredictable because price does not always move according to the data alone. Sometimes, the difference between actual results and market expectations matters more than the result itself.' },
          { type: 'callout', text: '<strong>In simple words:</strong> An economic calendar helps traders track important market events, while news trading involves making trading decisions based on economic announcements and market reactions.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided for general educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any currency or financial instrument. News trading involves high risk. Market conditions may become extremely volatile, spreads may widen, and price may move unpredictably. Economic calendar data and forecasts do not guarantee any specific price movement. Conduct your own research and consult a qualified financial advisor before making any financial decision.' },
        ]
      },
    ]
  },

  // ── TECHNICAL ANALYSIS ─────────────────────────────────────────────────────
  {
    id: 'technical-analysis', icon: '📐', title: 'Technical Analysis',
    desc: 'Charts, candlesticks, indicators, price action, patterns, SMC, volume, and risk management.',
    topics: [
      { id: 'what-is-ta', title: 'What is Technical Analysis?', level: 'Beginner', summary: 'The foundation of chart-based trading and its core principles.',
        content: [
          { type: 'image', src: 'images/SNRTA001.jpg', alt: 'What is Technical Analysis' },
          { type: 'paragraph', text: 'Technical Analysis is a method used by traders and investors to study market price movement through charts, patterns, volume, and indicators. Instead of focusing only on company news or financial statements, technical analysis focuses on how price behaves on the chart.' },
          { type: 'paragraph', text: 'The main idea behind technical analysis is simple: price reflects market psychology. Every candle, trendline, support level, resistance zone, and volume movement shows how buyers and sellers are reacting in the market.' },
          { type: 'paragraph', text: 'Technical analysis can be used in different financial markets, including stocks, commodities, crypto, and forex.' },
          { type: 'heading', text: 'Why Technical Analysis is Important' },
          { type: 'paragraph', text: 'Technical analysis helps traders understand the current market direction and identify possible trading opportunities. It allows traders to study whether the market is moving upward, downward, or sideways.' },
          { type: 'paragraph', text: 'By using technical analysis, traders can make more structured decisions instead of entering trades based on emotions, rumors, or random guesses.' },
          { type: 'paragraph', text: 'It helps in:' },
          { type: 'list', items: [
            'Identifying market trends',
            'Finding support and resistance levels',
            'Understanding buyer and seller behavior',
            'Planning entry and exit points',
            'Managing risk through stop loss and target levels',
            'Studying price momentum using indicators',
          ]},
          { type: 'heading', text: 'Key Elements of Technical Analysis' },
          { type: 'heading', text: '1. Price Charts' },
          { type: 'paragraph', text: 'Price charts are the foundation of technical analysis. They show how the price of an asset has moved over time. Traders commonly use line charts, bar charts, and candlestick charts.' },
          { type: 'paragraph', text: 'Among these, candlestick charts are the most popular because they show the open, high, low, and close price in a clear visual format.' },
          { type: 'heading', text: '2. Candlestick Patterns' },
          { type: 'paragraph', text: 'Candlestick patterns help traders understand market sentiment. Some patterns show buying pressure, while others show selling pressure.' },
          { type: 'paragraph', text: 'For example, bullish candles may suggest strength in the market, while bearish candles may suggest weakness. Patterns like engulfing candles, doji, hammer, and shooting star are commonly used by traders.' },
          { type: 'heading', text: '3. Support and Resistance' },
          { type: 'paragraph', text: 'Support is a price level where buyers may enter the market and stop the price from falling further.' },
          { type: 'paragraph', text: 'Resistance is a price level where sellers may become active and stop the price from rising further.' },
          { type: 'paragraph', text: 'These levels are important because markets often react around them. Traders use support and resistance to plan entries, exits, stop losses, and profit targets.' },
          { type: 'heading', text: '4. Trendlines and Market Structure' },
          { type: 'paragraph', text: 'Trendlines help traders identify the direction of the market. If price is making higher highs and higher lows, the market is usually in an uptrend. If price is making lower highs and lower lows, the market is usually in a downtrend.' },
          { type: 'paragraph', text: 'Understanding market structure helps traders avoid trading against the main direction of the market.' },
          { type: 'heading', text: '5. Indicators and Volume' },
          { type: 'paragraph', text: 'Indicators are tools that help traders analyze price momentum, trend strength, and possible reversal points. Common indicators include RSI, MACD, Moving Averages, Bollinger Bands, and Volume.' },
          { type: 'paragraph', text: 'Volume is also very important because it shows the strength behind a price move. A breakout with high volume is usually more meaningful than a breakout with weak volume.' },
          { type: 'heading', text: 'Technical Analysis Does Not Predict with 100% Accuracy' },
          { type: 'paragraph', text: 'Technical analysis is not a magic formula and it does not guarantee profit. It only helps traders analyze probability.' },
          { type: 'paragraph', text: 'A professional trader does not use technical analysis to predict the future with certainty. Instead, the goal is to create a trading plan based on probability, confirmation, and risk management.' },
          { type: 'paragraph', text: 'Even the best technical setup can fail, which is why stop loss and position sizing are very important.' },
          { type: 'heading', text: 'Technical Analysis vs Fundamental Analysis' },
          { type: 'paragraph', text: 'Technical analysis studies price charts, trends, volume, and patterns.' },
          { type: 'paragraph', text: 'Fundamental analysis studies financial statements, company performance, earnings, economic data, interest rates, and business value.' },
          { type: 'paragraph', text: 'Both methods are useful. Many traders use technical analysis for timing entries and exits, while investors use fundamental analysis to understand the long-term value of an asset.' },
          { type: 'heading', text: 'Final Thoughts' },
          { type: 'paragraph', text: 'Technical analysis is one of the most important skills for anyone who wants to understand financial markets. It helps traders read charts, identify trends, understand market behavior, and manage risk properly.' },
          { type: 'paragraph', text: 'For beginners, the best approach is to start with the basics: candlesticks, support and resistance, trendlines, volume, and risk management. Once these foundations are clear, advanced tools like indicators, chart patterns, and smart money concepts become easier to understand.' },
          { type: 'paragraph', text: 'In simple words, technical analysis helps traders read the language of the market through price charts.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is for educational purposes only and should not be considered financial advice. Trading and investing involve risk, and every learner should do proper research before making any financial decision.' },
        ]
      },
      { id: 'ta-vs-fa', title: 'Technical vs Fundamental Analysis', level: 'Beginner', summary: 'Comparing the two main schools of market analysis.',
        content: [
          { type: 'image', src: 'images/SNRTA002.jpg', alt: 'Technical vs Fundamental Analysis' },
          { type: 'paragraph', text: 'In trading and investing, two of the most widely used approaches for market analysis are Technical Analysis and Fundamental Analysis. Both methods help market participants make informed decisions, but they focus on different types of information.' },
          { type: 'heading', text: 'Technical Analysis' },
          { type: 'paragraph', text: 'Technical Analysis studies price action, chart patterns, volume, trends, support and resistance levels, indicators, and market behavior. It is based on the idea that price reflects all available information and that historical price movements can help identify possible future market direction. Traders often use technical analysis to find entry points, exit points, trend continuation signals, reversal areas, and risk management levels.' },
          { type: 'heading', text: 'Fundamental Analysis' },
          { type: 'paragraph', text: 'Fundamental Analysis focuses on the actual financial strength, business performance, economic environment, and intrinsic value of an asset. In stocks, this may include earnings, revenue growth, profit margins, debt levels, cash flow, management quality, industry outlook, and valuation ratios such as EPS, P/E ratio, book value, and dividend yield. Fundamental analysis is often used to determine whether an asset is undervalued, overvalued, or fairly priced.' },
          { type: 'heading', text: 'The Key Difference' },
          { type: 'paragraph', text: 'Technical Analysis focuses on price behavior, while Fundamental Analysis focuses on value and business quality. Technical analysts ask, "What is the price doing?" Fundamental analysts ask, "What is the asset really worth?"' },
          { type: 'heading', text: 'Which One to Use?' },
          { type: 'paragraph', text: 'For short-term trading, technical analysis is commonly used because it helps traders understand market timing, momentum, and price levels. For long-term investing, fundamental analysis is often preferred because it helps investors evaluate the financial health and future potential of a company or asset.' },
          { type: 'heading', text: 'Combining Both Approaches' },
          { type: 'paragraph', text: 'The strongest approach often comes from combining both methods. A trader or investor can use fundamental analysis to identify strong assets and technical analysis to decide the best time to enter or exit the market. For example, a fundamentally strong stock may still not be a good buy if the chart shows weak momentum or a major resistance zone. Similarly, a stock may look technically attractive, but poor fundamentals can increase risk.' },
          { type: 'paragraph', text: 'In professional trading, both approaches have value. Technical analysis improves timing and risk control, while fundamental analysis improves selection and long-term confidence. Understanding the difference between the two helps traders develop a more balanced, disciplined, and informed market strategy.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Technical Analysis helps you understand <em>when</em> to trade, while Fundamental Analysis helps you understand <em>what</em> to trade. Together, they provide a more complete view of the market.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> The content provided in this educational library is for general information and learning purposes only. It should not be considered as financial advice, investment advice, trading advice, or a recommendation to buy, sell, or hold any financial instrument. Trading and investing involve significant risk, including the possible loss of capital. Past performance, chart patterns, or historical market behavior do not guarantee future results. Every trader or investor must conduct their own research, apply proper risk management, and make decisions based on their personal financial situation and risk tolerance. By reading or using this material, you acknowledge that you are fully responsible for your own trading and investment decisions.' },
        ]
      },
      { id: 'price-action', title: 'Understanding Price Action', level: 'Beginner', summary: 'Reading raw price movement without indicators.',
        content: [
          { type: 'image', src: 'images/SNRTA003.jpg', alt: 'Understanding Price Action' },
          { type: 'paragraph', text: 'Price Action is one of the most important concepts in technical analysis. It refers to the study of price movement on a chart without depending heavily on indicators. Instead of focusing only on external tools, price action helps traders understand how the market is behaving through candles, trends, support and resistance levels, market structure, and key price zones.' },
          { type: 'paragraph', text: 'In simple words, price action shows the real-time battle between buyers and sellers. When buyers are stronger, price usually moves upward. When sellers dominate, price moves downward. By reading price action correctly, traders can identify possible trend direction, reversal areas, breakout opportunities, and risk zones.' },
          { type: 'heading', text: 'How Price Action Works' },
          { type: 'paragraph', text: 'A price action trader observes how price reacts at important levels. These levels may include previous highs and lows, support and resistance zones, supply and demand areas, trendlines, and consolidation ranges. For example, if price reaches a strong support zone and forms a bullish candle pattern, it may indicate that buyers are entering the market. Similarly, if price reaches resistance and starts rejecting that level, sellers may be gaining control.' },
          { type: 'heading', text: 'The Role of Candlestick Behavior' },
          { type: 'paragraph', text: 'Candlestick behavior is also a major part of price action. Candle size, wick length, body strength, and closing position can provide valuable information about market sentiment. A strong bullish candle may show buying pressure, while a long upper wick near resistance may show selling pressure. These small details help traders understand whether the market is showing strength, weakness, hesitation, or rejection.' },
          { type: 'heading', text: 'Why Price Action is Widely Used' },
          { type: 'paragraph', text: 'Price action is widely used because it provides a clean and direct view of the market. Unlike indicators, which are often based on past price data, price action focuses on what price is doing right now. This makes it useful for traders who want to understand market movement in a practical and professional way.' },
          { type: 'heading', text: 'Important Caution' },
          { type: 'paragraph', text: 'Price action should not be used randomly. A trader must combine it with proper market structure, risk management, and confirmation. Not every candle pattern or breakout is reliable. False breakouts, fake moves, and emotional trading can lead to losses if price action is not analyzed carefully.' },
          { type: 'heading', text: 'Key Questions Price Action Answers' },
          { type: 'paragraph', text: 'Professional traders often use price action to answer key questions such as:' },
          { type: 'list', items: [
            'Where is the market trending?',
            'Where are buyers and sellers active?',
            'Is price rejecting or accepting a level?',
            'Is the market forming a breakout, reversal, or continuation?',
            'Where should risk be managed?',
          ]},
          { type: 'heading', text: 'Price Action as the Foundation' },
          { type: 'paragraph', text: 'The main strength of price action is that it helps traders understand the logic behind market movement. Instead of blindly following signals, traders learn to read the chart, observe market behavior, and make more disciplined decisions.' },
          { type: 'paragraph', text: 'Whether a trader uses indicators, Smart Money Concepts, support and resistance, or candlestick patterns, understanding price action improves market reading and decision-making.' },
          { type: 'callout', text: '<strong>In simple words:</strong> Price Action helps traders understand what the market is doing, where buyers and sellers are active, and how price is reacting at important levels.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> The content provided in this educational library is for general information and learning purposes only. It should not be considered financial advice, investment advice, trading advice, or a recommendation to buy, sell, or hold any financial instrument. Trading and investing involve significant risk, including the possible loss of capital. Past performance, chart patterns, indicators, strategies, or historical market behavior do not guarantee future results. Any examples, charts, or strategies shared are for educational explanation only and should not be treated as direct trading signals. Every trader or investor must conduct their own research, apply proper risk management, and make decisions based on their personal financial situation and risk tolerance. By reading or using this material, you acknowledge that you are fully responsible for your own trading and investment decisions.' },
        ]
      },
      { id: 'candlestick-charts', title: 'Candlestick Charts Explained', level: 'Beginner', summary: 'How to read and interpret candlestick charts.',
        content: [
          { type: 'image', src: 'images/SNRTA004.jpg', alt: 'Candlestick Charts Explained' },
          { type: 'paragraph', text: 'Candlestick charts are a core visual framework used to interpret price movement across financial markets. Each candlestick represents the open, high, low, and close of price within a selected time period. Professional candlestick analysis is not about memorizing candle colors — it is about understanding buyer-seller pressure, rejection, volatility, momentum, liquidity interaction, and market acceptance or failure at key price zones.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'The candle body represents the difference between the opening and closing price. A wide body usually reflects conviction, while a narrow body may indicate hesitation or balance. The wicks show the highest and lowest price attempts during the period. Long wicks often reveal rejection, liquidity testing, or failed attempts to continue in one direction. A bullish candle closing near its high may indicate strong demand. A bearish candle closing near its low may indicate strong supply. However, the same bullish candle has different meaning if it appears at support, in the middle of a range, or directly into resistance.' },
          { type: 'image', src: 'images/SNRTA004_A.jpg', alt: 'Candlestick anatomy — body, wicks, open and close' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders use candlestick charts to assess price reaction around important zones. They observe whether price is accepting above resistance, rejecting from supply, absorbing selling pressure, or losing momentum after an extended move. Candlestick analysis becomes more reliable when combined with support and resistance, volume, market structure, higher-timeframe bias, and risk-reward planning. A candle is not a trade signal by itself; it is evidence within a broader decision-making framework.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'A major mistake is treating a single candle as a guaranteed market prediction. A hammer is not automatically bullish, and a shooting star is not automatically bearish. Context determines quality. Another mistake is ignoring timeframe alignment — a strong candle on a lower timeframe may have little importance if it forms against a major higher-timeframe structure.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Candlestick charts are essential for reading price behavior, but their true value comes from contextual interpretation. Professional traders use candlesticks to understand market intent, rejection, momentum, and decision-making around key zones.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Candlestick analysis is interpretive and does not guarantee future price movement. Conduct independent analysis, apply appropriate risk management, and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'candlestick-patterns', title: 'Most Important Candlestick Patterns', level: 'Beginner', summary: 'The key candlestick formations every trader must know.',
        content: [
          { type: 'image', src: 'images/SNRTA005.jpg', alt: 'Most Important Candlestick Patterns' },
          { type: 'paragraph', text: 'Candlestick patterns are recurring candle formations that help traders interpret changes in market psychology. They can suggest continuation, reversal, rejection, exhaustion, or indecision. In professional technical analysis, candlestick patterns are not used as standalone signals — their value depends on market location, trend context, volume, structure, and confirmation.' },
          { type: 'heading', text: 'Bullish, Bearish, and Indecision Patterns' },
          { type: 'paragraph', text: 'Bullish patterns such as bullish engulfing, hammer, morning star, and piercing patterns may indicate that buyers are entering or sellers are losing control. Bearish patterns such as bearish engulfing, shooting star, evening star, and hanging man may indicate increasing supply or weakening demand. Indecision candles such as doji and spinning tops represent uncertainty between buyers and sellers, particularly important near major support, resistance, or liquidity zones.' },
          { type: 'image', src: 'images/SNRTA005_A.jpg', alt: 'Bullish and bearish candlestick patterns' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders evaluate candlestick patterns by asking where the pattern forms and what it confirms. A bullish engulfing candle at higher-timeframe support after a liquidity sweep has more analytical value than the same pattern appearing randomly within a sideways range. Patterns are most useful when they support an existing thesis, with volume confirmation, favorable risk-reward, and broader trend alignment.' },
          { type: 'image', src: 'images/SNRTA005_B.jpg', alt: 'Candlestick patterns in professional chart context' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'A common mistake is memorizing pattern names without understanding market behavior. Candlestick patterns are not magical formations — they are visual expressions of order flow and market participation. Another mistake is entering immediately after a pattern without checking liquidity, trend direction, or invalidation level.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Candlestick patterns help identify possible shifts in momentum and control, but they require professional context. Their reliability improves when aligned with structure, volume, liquidity, trend direction, and disciplined risk management.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Candlestick patterns may fail or produce false signals during volatile, illiquid, or news-driven conditions. Conduct independent research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'support-resistance', title: 'Support and Resistance', level: 'Beginner', summary: 'Identifying key price levels where the market reacts.',
        content: [
          { type: 'image', src: 'images/SNRTA006.jpg', alt: 'Support and Resistance' },
          { type: 'paragraph', text: 'Support and resistance are structural price zones where market participants have historically shown meaningful buying or selling interest. In professional analysis, they are not treated as simple lines on a chart — they are decision zones where liquidity, order flow, psychology, volume, and historical price reaction interact.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'Support forms where demand may be strong enough to slow or reverse selling pressure. Resistance forms where supply may be strong enough to slow or reverse buying pressure. These areas develop because traders, investors, institutions, and algorithms respond to previous price behavior. Support and resistance are better understood as zones rather than exact prices — price may briefly pierce a level to collect liquidity before reversing.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Support and resistance are used for identifying trade location, planning entries, placing stop-losses, setting profit targets, and evaluating risk-reward. High-quality zones are often supported by confluence such as higher-timeframe structure, volume concentration, previous swing levels, or psychological price areas. Role reversal is another key concept: when resistance breaks and price holds above it, that zone may act as future support, and vice versa.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'One mistake is drawing too many levels, making the chart confusing and reducing decision quality. Another mistake is assuming that a level becomes stronger every time it is tested. In reality, repeated testing can weaken a level as available orders are absorbed.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Support and resistance are essential for market structure analysis, but their real value lies in interpreting how price behaves around them. Professional traders use them as decision zones, not guaranteed reversal points.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Support and resistance levels are analytical estimates and may fail due to volatility, news, liquidity sweeps, or unexpected order flow. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'trendlines-channels', title: 'Trendlines and Channels', level: 'Beginner', summary: 'Drawing and trading dynamic support and resistance.',
        content: [
          { type: 'image', src: 'images/SNRTA007.jpg', alt: 'Trendlines and Channels' },
          { type: 'paragraph', text: 'Trendlines and channels are technical tools used to define market direction, momentum boundaries, and dynamic support or resistance. They help traders visualize whether price is moving in a structured upward, downward, or sideways manner.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'An upward trendline connects meaningful higher lows, showing that buyers are entering at progressively higher prices. A downward trendline connects meaningful lower highs, showing that sellers are defending lower price areas. A channel forms when price moves between two parallel boundaries. Ascending channels show controlled bullish movement, descending channels show controlled bearish movement, and horizontal channels show market balance or consolidation.' },
          { type: 'image', src: 'images/SNRTA007_A.jpg', alt: 'Trendline and channel structure examples' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders use trendlines and channels to identify pullback zones, continuation setups, breakout areas, overextension, and potential trend exhaustion. A trendline break may suggest a shift in momentum, but does not automatically confirm a trend reversal. A high-quality trendline usually connects clear swing points, aligns with broader structure, and is respected by price multiple times without excessive forcing.' },
          { type: 'image', src: 'images/SNRTA007_B.jpg', alt: 'Trendlines and channels on a professional chart' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'Trendlines are subjective. Traders often draw lines to fit their bias rather than the market structure. Another mistake is treating every trendline break as a reversal — sometimes a break is only a deeper pullback, liquidity sweep, or temporary volatility expansion.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Trendlines and channels help define market rhythm and directional structure. Their professional value increases when used with market structure, volume, support-resistance, and confirmation rather than as isolated drawing tools.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Trendlines and channels are interpretive tools and may be drawn differently by different analysts. Breaks and rejections may fail. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'market-structure', title: 'Market Structure: HH and LL', level: 'Beginner', summary: 'Reading the sequence of highs and lows to define trend.',
        content: [
          { type: 'image', src: 'images/SNRTA008.jpg', alt: 'Market Structure HH and LL' },
          { type: 'paragraph', text: 'Market structure is the organized reading of swing highs and swing lows to determine trend direction, market strength, weakness, continuation, or transition. It is one of the most important foundations of technical analysis because it tells traders whether price is trending upward, trending downward, or moving sideways.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'In an uptrend, price typically forms higher highs and higher lows. A higher high indicates that buyers are capable of pushing price beyond previous resistance. A higher low shows that sellers are unable to drive price back to the prior low, confirming demand at higher levels. In a downtrend, price typically forms lower lows and lower highs. Market structure includes HH, HL, LH, and LL — these swing points define the current trend state and help traders avoid trading against dominant structure without confirmation.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders use market structure to determine bias, entry quality, stop placement, and exit logic. Buying in a sequence of lower highs and lower lows is usually lower probability unless there is evidence of structural transition. Market structure is also the foundation of advanced concepts such as Break of Structure, Change of Character, liquidity sweeps, inducement, and order block analysis.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'A common mistake is identifying swing points too aggressively on very low timeframes, creating noise and false structure. Another mistake is assuming one broken high or low automatically confirms a full reversal. Professional traders distinguish between minor structure and major structure.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Market structure gives traders a framework for understanding trend direction and market control. It helps identify whether buyers or sellers are dominant and whether a market is continuing, weakening, or transitioning.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Market structure analysis is subjective and may vary by timeframe and market conditions. Structural signals may fail or reverse unexpectedly. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'dow-theory', title: 'Dow Theory for Beginners', level: 'Beginner', summary: 'The original framework for understanding market trends.',
        content: [
          { type: 'image', src: 'images/SNRTA009.jpg', alt: 'Dow Theory for Beginners' },
          { type: 'paragraph', text: 'Dow Theory is one of the earliest and most respected foundations of technical analysis. It provides a framework for understanding market trends, confirmation, price behavior, and the relationship between market movement and investor psychology.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'Dow Theory suggests that markets move in trends which can be primary, secondary, or minor. The primary trend reflects the major market direction. Secondary trends are corrections or counter-moves within the primary trend. Minor trends represent short-term fluctuations. Another key principle is that price discounts available information — market prices reflect expectations, news, sentiment, and investor behavior. Dow Theory also emphasizes confirmation, meaning a trend is more reliable when supported by broader market participation.' },
          { type: 'image', src: 'images/SNRTA009_A.jpg', alt: 'Dow Theory primary secondary and minor trend phases' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders use Dow Theory to distinguish between major directional movement and short-term noise. It helps identify trend phases, avoid premature reversal assumptions, and understand whether market movement is broadly supported. Volume confirmation is also important — in a healthy trend, volume often expands in the direction of the trend and contracts during corrective phases.' },
          { type: 'image', src: 'images/SNRTA009_B.jpg', alt: 'Volume confirmation with Dow Theory trend direction' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'Beginners often assume Dow Theory is outdated because it is old. In reality, its principles remain relevant because market psychology, trend behavior, and confirmation still influence modern markets. Another mistake is using Dow Theory as a precise timing tool — it is better suited for structural understanding than exact entry execution.' },
          { type: 'image', src: 'images/SNRTA009_C.jpg', alt: 'Distinguishing major and minor market moves using Dow Theory' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Dow Theory provides a classical but powerful framework for understanding trend direction, confirmation, and market behavior. It remains relevant because it focuses on principles rather than short-term indicators.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Dow Theory is an analytical framework and does not guarantee accurate market prediction. Trends may fail or remain unclear for extended periods. Conduct independent research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'breakout-trading', title: 'Breakout and Breakdown Trading', level: 'Intermediate', summary: 'Trading decisive moves beyond key levels.',
        content: [
          { type: 'image', src: 'images/SNRTA010.jpg', alt: 'Breakout and Breakdown Trading' },
          { type: 'paragraph', text: 'Breakout and breakdown trading focuses on price movement beyond important market structure levels. A breakout occurs when price moves above resistance, while a breakdown occurs when price moves below support. These events may indicate directional expansion, trend continuation, or the beginning of a new price phase.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'A breakout suggests that demand has become strong enough to absorb supply at resistance. A breakdown suggests that supply has overwhelmed demand at support. However, price crossing a level is not enough. Professional traders look for acceptance beyond the level, strong closing behavior, volume expansion, and follow-through. Breakouts often occur after consolidation, compression, triangles, flags, or volatility contraction — the longer price compresses, the more significant the eventual expansion may become.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders may enter on confirmation, retest, or continuation after the breakout. They define invalidation levels before execution and calculate risk-reward based on structure. Breakout targets may be based on measured moves, previous liquidity zones, higher-timeframe resistance, or volatility projections. Breakdown trading follows the same logic in bearish conditions.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'A major mistake is entering as soon as price pierces a level. Many breakouts fail because price only moves beyond the level to trigger orders before reversing. Another mistake is ignoring volume — a breakout without participation may lack sustainability.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Breakout and breakdown trading can capture strong directional moves, but quality depends on confirmation, volume, market context, liquidity, and execution discipline.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Breakouts and breakdowns may fail, reverse, or become liquidity traps. Conduct independent analysis, apply strict risk management, and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'fake-breakouts', title: 'Fake Breakouts and Liquidity Traps', level: 'Intermediate', summary: 'Identifying and avoiding false breakout setups.',
        content: [
          { type: 'image', src: 'images/SNRTA011.jpg', alt: 'Fake Breakouts and Liquidity Traps' },
          { type: 'paragraph', text: 'Fake breakouts and liquidity traps occur when price temporarily moves beyond a visible level but fails to continue, often reversing sharply back into the prior structure. These events reveal how liquidity, stop-loss clusters, breakout orders, and emotional participation can influence market movement.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'Obvious highs and lows often attract liquidity. Traders place stop-loss orders above resistance and below support. When price moves into these zones, liquidity becomes available. If the market cannot sustain movement beyond the level, price may reverse and trap late participants. A bullish fake breakout occurs when price breaks above resistance, attracts buyers, and then falls back below the level. A bearish fake breakdown occurs when price breaks below support, attracts sellers, and then reverses upward.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders watch for weak closes beyond levels, long rejection wicks, lack of volume follow-through, immediate return into range, and failure to hold retests. These signals may indicate that a breakout is not being accepted by the market. Liquidity traps can also provide opportunities — if price sweeps a level and then shows strong displacement in the opposite direction, traders may look for continuation toward the opposite liquidity area.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'Not every failed breakout is manipulation, and not every liquidity sweep leads to reversal. Sometimes price breaks a level, retests it, and continues. Professional analysis requires confirmation rather than assumption.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Fake breakouts and liquidity traps highlight the importance of confirmation. They teach traders that obvious levels can attract liquidity before the real directional move develops.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Liquidity trap analysis is interpretive and may not accurately predict future market behavior. Conduct independent analysis, apply strict risk management, and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'volume-analysis', title: 'Volume Analysis', level: 'Intermediate', summary: 'Using volume to confirm price moves and spot reversals.',
        content: [
          { type: 'image', src: 'images/SNRTA012.jpg', alt: 'Volume Analysis' },
          { type: 'paragraph', text: 'Volume analysis evaluates the level of market participation behind price movement. It helps traders understand whether a move is supported by strong participation or occurring with weak conviction. In professional analysis, volume is used to assess confirmation, accumulation, distribution, breakout quality, exhaustion, and liquidity.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'Price movement with increasing volume often suggests stronger conviction. Price movement with declining volume may indicate weaker participation. However, volume must be interpreted with price behavior. High volume with strong directional close may confirm momentum. High volume with little price progress may indicate absorption. Volume spikes can reveal important market events such as institutional activity, panic selling, aggressive buying, or breakout participation.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders compare current volume with average volume. A breakout above resistance with significantly above-average volume may be more meaningful than a breakout on low volume. Volume can also help identify accumulation near lows and distribution near highs. In stock trading, volume is particularly important because liquidity affects execution quality.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'One mistake is assuming high volume is always bullish — high volume can represent aggressive selling, distribution, or panic. Another mistake is ignoring the relationship between volume and candle close. The same volume figure can mean different things depending on price reaction.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Volume analysis adds depth to price analysis by revealing participation and conviction. It should be used with price action, structure, trend, and liquidity conditions.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Volume interpretation may be affected by market structure, hidden orders, and news events. Volume confirmation does not guarantee successful trades. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'moving-averages', title: 'Moving Averages: SMA and EMA', level: 'Beginner', summary: 'How moving averages smooth price and signal trend direction.',
        content: [
          { type: 'image', src: 'images/SNRTA013.jpg', alt: 'Moving Averages SMA and EMA' },
          { type: 'paragraph', text: 'Moving averages are trend-following tools used to smooth price data and identify directional bias, momentum, and dynamic support or resistance. The Simple Moving Average and Exponential Moving Average are two of the most commonly used versions.' },
          { type: 'heading', text: 'SMA vs EMA' },
          { type: 'paragraph', text: 'The Simple Moving Average calculates the average closing price over a selected period, giving equal weight to each data point. The Exponential Moving Average gives more weight to recent prices, making it more responsive to current price changes. When price remains above a key moving average, trend conditions may be bullish. When price remains below it, trend conditions may be bearish.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders use moving averages for trend filtering, pullback entries, dynamic support-resistance, momentum evaluation, and crossovers. A 50-period moving average may help identify medium-term trend, while a 200-period moving average may define long-term market bias. EMA is often preferred by short-term traders because it responds faster, while SMA is commonly used for broader market observation. Moving averages are most effective in trending markets and less reliable during sideways consolidation.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'A major mistake is treating moving average crossovers as automatic buy or sell signals. Crossovers often lag price and may produce false signals in choppy markets. Another mistake is using too many moving averages, which creates confusion rather than clarity.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> SMA and EMA are useful for identifying trend direction and momentum, but they must be applied within market structure and supported by risk management.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to use any indicator or trade any financial instrument. Moving averages are lagging tools and may produce false signals, especially in sideways or volatile markets. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'rsi-indicator', title: 'RSI Indicator Explained', level: 'Beginner', summary: 'Using RSI to spot overbought and oversold conditions.',
        content: [
          { type: 'image', src: 'images/SNRTA014.jpg', alt: 'RSI Indicator Explained' },
          { type: 'paragraph', text: 'The Relative Strength Index, commonly known as RSI, is a momentum oscillator used to measure the speed and strength of price movement. It helps traders assess momentum conditions, overextension, divergence, and possible shifts in market strength.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'RSI is displayed on a scale from 0 to 100. Traditional interpretation considers readings above 70 as overbought and readings below 30 as oversold. However, professional traders understand that these levels do not automatically mean reversal. In strong trends, RSI can remain overbought or oversold for extended periods. RSI is more valuable when used to evaluate momentum behavior — rising RSI confirms strengthening upside momentum, while falling RSI confirms increasing downside momentum.' },
          { type: 'heading', text: 'Divergence Analysis' },
          { type: 'paragraph', text: 'RSI is widely used for divergence analysis. Bullish divergence occurs when price makes a lower low while RSI makes a higher low, suggesting weakening selling momentum. Bearish divergence occurs when price makes a higher high while RSI makes a lower high, suggesting weakening buying momentum. Hidden divergence may support trend continuation.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'A common mistake is selling every overbought reading or buying every oversold reading — this approach is dangerous in trending markets. Another mistake is using RSI without checking market structure, support-resistance, and higher-timeframe direction.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> RSI is a momentum analysis tool, not a standalone signal generator. Its professional value comes from understanding momentum strength, divergence, trend context, and confirmation.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to use RSI or trade any financial instrument. RSI signals may fail, remain extreme for extended periods, or provide misleading divergence during strong trends. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'macd-indicator', title: 'MACD Indicator Explained', level: 'Intermediate', summary: 'The MACD indicator in practice — signal line, histogram, divergence.',
        content: [
          { type: 'image', src: 'images/SNRTA015.jpg', alt: 'MACD Indicator Explained' },
          { type: 'paragraph', text: 'The Moving Average Convergence Divergence indicator, known as MACD, is a momentum and trend-following indicator used to evaluate changes in directional strength. It helps traders identify momentum shifts, trend confirmation, and possible changes in market behavior.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'MACD typically consists of the MACD line, signal line, and histogram. The MACD line reflects the relationship between two exponential moving averages. The signal line smooths the MACD line. The histogram shows the distance between the two lines and visually represents momentum expansion or contraction. When the MACD line crosses above the signal line, bullish momentum may be improving. When it crosses below, bearish momentum may be increasing — but crossovers are not automatic trade signals.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders use MACD to confirm trend strength, identify momentum loss, and detect divergence. If price makes a new high but MACD fails to confirm, upside momentum may be weakening. If price makes a new low but MACD improves, downside pressure may be fading. MACD is more effective in trending environments and should be combined with price action, structure, support-resistance, and volume.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'The most common mistake is using MACD crossovers mechanically. Because MACD is based on moving averages, it can lag behind price. Another mistake is ignoring market condition — MACD signals can be unreliable in choppy ranges.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> MACD helps evaluate trend momentum and directional strength, but professional use requires context, confirmation, and risk control.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to use MACD or trade any financial instrument. MACD is a lagging indicator and may generate false signals, especially in sideways or volatile markets. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'bollinger-bands', title: 'Bollinger Bands Explained', level: 'Intermediate', summary: 'Using Bollinger Bands to gauge volatility and price extremes.',
        content: [
          { type: 'image', src: 'images/SNRTA016.jpg', alt: 'Bollinger Bands Explained' },
          { type: 'paragraph', text: 'Bollinger Bands are volatility-based bands plotted around a moving average. They help traders evaluate volatility expansion, volatility contraction, overextension, mean reversion, and potential breakout conditions.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'Bollinger Bands usually consist of a middle moving average and two outer bands based on standard deviation. When volatility increases, the bands expand. When volatility decreases, the bands contract. Price touching the upper band does not automatically mean the asset should be sold, and price touching the lower band does not automatically mean the asset should be bought. In strong trends, price can continue moving along the outer bands.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'A Bollinger Band squeeze occurs when the bands narrow significantly, indicating low volatility that may precede a larger directional move. Professional traders wait for confirmation through price action, volume, structure, and breakout quality. In range-bound markets, Bollinger Bands may support mean-reversion strategies. In trending markets, they may help identify momentum continuation. The correct interpretation depends on market condition.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'A common mistake is assuming every outer band touch is a reversal signal. Another mistake is using Bollinger Bands without distinguishing between trending and ranging environments, which can lead to poor entries during strong directional moves.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Bollinger Bands help traders understand volatility behavior, but they require market context. Their value lies in interpreting compression, expansion, overextension, and price acceptance.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to use any indicator or trade any financial instrument. Bollinger Bands may produce false signals, especially during strong trends or sudden volatility events. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'fibonacci', title: 'Fibonacci Retracement and Extension', level: 'Intermediate', summary: 'Using Fibonacci levels to find high-probability entries and targets.',
        content: [
          { type: 'image', src: 'images/SNRTA017.jpg', alt: 'Fibonacci Retracement and Extension' },
          { type: 'paragraph', text: 'Fibonacci retracement and extension tools are used to identify potential reaction levels, pullback zones, continuation areas, and projected targets. They are widely applied in technical analysis because markets often react around proportional price relationships.' },
          { type: 'heading', text: 'Retracement Levels' },
          { type: 'paragraph', text: 'Fibonacci retracement is used to measure potential pullback levels within a trend. Common retracement levels include 38.2%, 50%, 61.8%, and 78.6%. In an uptrend, traders use retracement levels to identify possible demand zones. In a downtrend, they use them to identify possible resistance zones.' },
          { type: 'heading', text: 'Extension Levels and Professional Application' },
          { type: 'paragraph', text: 'Fibonacci extension is used to project potential target areas beyond the original swing, with common levels at 127.2%, 161.8%, and 200%. Professional traders do not treat Fibonacci levels as guaranteed turning points — these levels are most useful when they align with structure, support-resistance, order blocks, trendlines, or higher-timeframe levels. Correct swing selection is critical; poorly selected highs and lows produce weak levels.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'A common mistake is assuming Fibonacci works because of the number itself. In professional practice, Fibonacci levels matter because many market participants watch them and because they often align with natural pullback behavior. Another mistake is entering without confirmation from price action or structure.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Fibonacci tools help identify possible reaction and target zones, but their reliability improves only when combined with structure, confluence, and risk management.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Fibonacci levels are analytical tools and do not guarantee price reaction or continuation. Swing selection is subjective and levels may fail. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'chart-patterns-shapes', title: 'Chart Patterns: Triangle, Flag, Wedge', level: 'Intermediate', summary: 'Recognising and trading the most common continuation and reversal patterns.',
        content: [
          { type: 'image', src: 'images/SNRTA018.jpg', alt: 'Chart Patterns Triangle Flag Wedge' },
          { type: 'paragraph', text: 'Chart patterns such as triangles, flags, and wedges represent structured price behavior created by consolidation, compression, continuation, or exhaustion. These patterns help traders understand how price is preparing for a possible directional move.' },
          { type: 'heading', text: 'Triangles' },
          { type: 'paragraph', text: 'Triangles form when price compresses between converging trendlines. Ascending triangles may show buyer pressure near resistance. Descending triangles may show seller pressure near support. Symmetrical triangles show balanced compression before directional expansion.' },
          { type: 'heading', text: 'Flags and Wedges' },
          { type: 'paragraph', text: 'Flags usually form after strong impulsive moves and represent controlled pullbacks. Bullish flags may support continuation after an upward move, while bearish flags may support continuation after a downward move. Wedges form when price narrows within converging boundaries. Rising wedges may indicate weakening bullish momentum, while falling wedges may indicate weakening bearish momentum.' },
          { type: 'heading', text: 'Professional Application and Misinterpretations' },
          { type: 'paragraph', text: 'Professional traders evaluate pattern quality based on trend context, volume behavior, breakout direction, retest confirmation, and higher-timeframe structure. Volume contraction during consolidation and expansion during breakout may improve confirmation. Many traders force patterns onto charts — another mistake is entering before confirmation. Patterns can fail, evolve into larger structures, or act as liquidity traps.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Triangles, flags, and wedges are useful for analyzing compression and continuation, but their professional value depends on context, confirmation, and disciplined execution.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Chart patterns may fail, reverse, or become liquidity traps. Pattern interpretation is subjective. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'head-and-shoulders', title: 'Head and Shoulders Pattern', level: 'Intermediate', summary: 'The classic reversal pattern and how to trade it.',
        content: [
          { type: 'image', src: 'images/SNRTA019.jpg', alt: 'Head and Shoulders Pattern' },
          { type: 'paragraph', text: 'The Head and Shoulders pattern is a structural reversal formation used to identify potential trend exhaustion. It commonly appears after an uptrend and may suggest that buyers are losing control. Its inverse version may appear after a downtrend and suggest weakening seller dominance.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'A standard Head and Shoulders pattern consists of a left shoulder, head, right shoulder, and neckline. The head forms a higher high, but the right shoulder fails to continue the trend. This failure may indicate weakening momentum and a shift in control. The neckline represents a key structural support area — a breakdown below the neckline may confirm bearish transition. In an inverse Head and Shoulders, a breakout above the neckline may confirm bullish transition.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders evaluate symmetry, volume, neckline slope, momentum divergence, and higher-timeframe context. Volume often declines during the formation and may expand during the neckline break. Targets are commonly projected by measuring the distance from the head to the neckline, but this projection is only an estimate. Risk management remains more important than target expectation.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'A common mistake is identifying incomplete patterns too early. Another mistake is assuming the neckline break guarantees continuation — failed Head and Shoulders patterns can produce powerful moves in the opposite direction.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> The Head and Shoulders pattern helps identify possible trend exhaustion and structural reversal, but it requires confirmation, volume analysis, and risk planning.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Head and Shoulders patterns may fail or produce false signals. Measured targets are estimates, not guarantees. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'double-top-bottom', title: 'Double Top and Double Bottom', level: 'Intermediate', summary: 'Identifying twin-peak and twin-valley reversal setups.',
        content: [
          { type: 'image', src: 'images/SNRTA020.jpg', alt: 'Double Top and Double Bottom' },
          { type: 'paragraph', text: 'Double Top and Double Bottom patterns are reversal structures that form when price tests a major level twice and fails to break through with conviction. These patterns help traders identify potential exhaustion at resistance or support.' },
          { type: 'heading', text: 'Double Top' },
          { type: 'paragraph', text: 'A Double Top forms when price rallies into resistance, pulls back, and then fails to break above the same zone on a second attempt. This may indicate buyer exhaustion and seller defense. Confirmation usually occurs when price breaks below the intermediate support, often called the neckline.' },
          { type: 'heading', text: 'Double Bottom' },
          { type: 'paragraph', text: 'A Double Bottom forms when price declines into support, rebounds, and then fails to break lower on a second attempt. This may indicate seller exhaustion and buyer defense. Confirmation occurs when price breaks above the intermediate resistance.' },
          { type: 'heading', text: 'Professional Application and Misinterpretations' },
          { type: 'paragraph', text: 'Professional traders analyze whether the second top or bottom forms with weaker momentum, lower volume, divergence, or rejection candles. The pattern is more meaningful when it forms at higher-timeframe levels, after extended trends, or around major liquidity zones. A common mistake is entering immediately after the second test without confirmation. Double tops and bottoms may also fail and become continuation patterns.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Double Top and Double Bottom patterns help identify potential reversal zones, but professional confirmation requires structure, volume, momentum, and risk-reward alignment.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Double Top and Double Bottom patterns may fail or continue in the original trend. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'multi-timeframe', title: 'Multi-Timeframe Analysis', level: 'Intermediate', summary: 'Using higher timeframes to confirm lower timeframe signals.',
        content: [
          { type: 'image', src: 'images/SNRTA021.jpg', alt: 'Multi-Timeframe Analysis' },
          { type: 'paragraph', text: 'Multi-timeframe analysis is the process of studying the same market across different timeframes to develop a complete understanding of trend, structure, liquidity, and execution quality. It helps traders avoid making decisions based on one isolated chart.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'Higher timeframes provide macro structure, major support-resistance, and dominant trend direction. Medium timeframes help identify setup quality and structural development. Lower timeframes assist with refined entries, stop placement, and execution timing. A market may appear bullish on a lower timeframe while still being bearish on a higher timeframe — multi-timeframe analysis helps traders understand whether a setup aligns with the broader market.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'A professional top-down process may begin with the weekly or daily chart to identify bias, then move to the 4-hour or 1-hour chart for structure, and finally use lower timeframes for execution. The exact combination depends on trading style. Scalpers, swing traders, and position traders all use multi-timeframe logic differently. The key is consistency and avoiding excessive timeframe switching.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'A common mistake is using too many timeframes, causing analysis paralysis. Another mistake is using lower-timeframe signals against major higher-timeframe resistance or support without understanding the risk.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Multi-timeframe analysis improves decision quality by aligning broad market structure with precise execution. It is essential for professional trade planning.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Multi-timeframe analysis may still produce conflicting or false signals. Timeframe selection depends on strategy, experience, and risk tolerance. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'smc-intro', title: 'Smart Money Concepts Introduction', level: 'Advanced', summary: 'Understanding how institutional traders move markets.',
        content: [
          { type: 'image', src: 'images/SNRTA022.jpg', alt: 'Smart Money Concepts Introduction' },
          { type: 'paragraph', text: 'Smart Money Concepts, commonly known as SMC, is an advanced technical analysis framework focused on liquidity, institutional-style price behavior, market structure, order flow logic, and price inefficiencies. It attempts to explain why price often moves toward certain areas before making major directional moves.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'The foundation of SMC is liquidity. Liquidity exists where orders are likely concentrated, such as above equal highs, below equal lows, around previous swing points, near trendlines, and beyond obvious support-resistance levels. Markets often move toward liquidity because large participants need sufficient order flow to enter or exit positions. After liquidity is collected, price may displace in the opposite direction or continue depending on market intent.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'SMC traders study liquidity sweeps, Break of Structure, Change of Character, Order Blocks, Fair Value Gaps, premium-discount zones, inducement, and mitigation. A professional workflow begins with higher-timeframe bias, then identifies liquidity pools, structural shifts, imbalance zones, and execution areas. SMC is most valuable when it provides a structured explanation of price behavior rather than being used as random terminology.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'Many traders misuse SMC by labeling every candle as an order block or every gap as a trade opportunity. Another mistake is believing SMC reveals guaranteed institutional activity — it is an analytical framework, not insider knowledge.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Smart Money Concepts provide a deeper way to study liquidity and structure, but they require discipline, confirmation, and risk management.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Smart Money Concepts are interpretive analytical tools and do not guarantee future price movement or trade success. Conduct independent analysis, apply strict risk management, and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'ob-fvg-bos-choch', title: 'Order Blocks, FVG, BOS and CHOCH', level: 'Advanced', summary: 'Key SMC concepts for identifying institutional footprints.',
        content: [
          { type: 'image', src: 'images/SNRTA023.jpg', alt: 'Order Blocks FVG BOS and CHOCH' },
          { type: 'paragraph', text: 'Order Blocks, Fair Value Gaps, Break of Structure, and Change of Character are advanced price-action concepts used within Smart Money Concepts and institutional-style technical analysis. They help traders interpret structural shifts, imbalance, liquidity interaction, and potential reaction zones.' },
          { type: 'heading', text: 'Core Concepts' },
          { type: 'paragraph', text: 'An Order Block is generally viewed as a price zone where significant buying or selling activity may have occurred before a strong directional move. A Fair Value Gap represents an imbalance created when price moves rapidly, leaving inefficient delivery between candles. Break of Structure occurs when price breaks a meaningful swing point in the direction of trend, suggesting continuation. Change of Character occurs when price violates previous structure against the existing trend, potentially signaling transition or reversal.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders do not use these concepts mechanically. A valid order block is more meaningful when preceded by liquidity collection and followed by strong displacement. A fair value gap is more important when aligned with higher-timeframe bias and structure. BOS and CHOCH help define whether the market is continuing or transitioning, but not every minor break qualifies as structural confirmation — major and minor structure must be separated.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'A common mistake is marking too many order blocks and FVGs, making the chart unusable. Another mistake is entering every FVG fill or order block touch without confirmation. Context is more important than labels.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Order Blocks, FVG, BOS, and CHOCH provide a sophisticated framework for reading liquidity, imbalance, structure, and transition, but they require precision and disciplined validation.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. These concepts are interpretive and may fail or be incorrectly identified. They do not guarantee reversal, continuation, or profitability. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'risk-reward', title: 'Risk Reward Ratio in Trading', level: 'Beginner', summary: 'Why your risk-to-reward ratio determines long-term profitability.',
        content: [
          { type: 'image', src: 'images/SNRTA024.jpg', alt: 'Risk Reward Ratio in Trading' },
          { type: 'paragraph', text: 'Risk Reward Ratio is a core trading discipline that compares the potential loss of a trade with its potential gain. It helps traders evaluate whether a setup offers sufficient reward relative to the capital being risked.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'If a trader risks 1 unit to potentially make 2 units, the risk-reward ratio is 1:2 — the trade offers twice the potential reward compared to the potential risk. However, risk-reward cannot be evaluated without probability. A high reward target is meaningless if the probability of reaching it is very low. Risk-reward planning requires three components: entry price, stop-loss level, and target level. The stop defines risk, the target defines reward, and the relationship between them determines whether the trade is structurally reasonable.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders use risk-reward to filter trades. A technically valid setup may still be rejected if the stop is too wide, the target is too close, or the probability is weak. Risk-reward also helps manage long-term performance — a trader with a 1:2 average reward may remain profitable even with a lower win rate, provided execution and risk control are consistent.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'A common mistake is chasing unrealistic reward ratios. Another mistake is ignoring win rate — risk-reward and probability must be analyzed together. A strategy must have positive expectancy, not just attractive targets.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Risk Reward Ratio is a professional decision filter that protects traders from low-quality setups and supports disciplined capital management.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. A favorable risk-reward ratio does not guarantee profitability. Stop-losses and targets may be affected by slippage, gaps, volatility, and liquidity. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'sl-tp-planning', title: 'Stop Loss and Take Profit Planning', level: 'Beginner', summary: 'Placing logical stop losses and take profit levels on every trade.',
        content: [
          { type: 'image', src: 'images/SNRTA025.jpg', alt: 'Stop Loss and Take Profit Planning' },
          { type: 'paragraph', text: 'Stop loss and take profit planning are essential components of professional trade management. They define how risk is controlled, how profits are realized, and how emotional decision-making is reduced before entering a trade.' },
          { type: 'heading', text: 'Core Market Logic' },
          { type: 'paragraph', text: 'A stop loss is a predefined exit level used to limit loss if the market moves against the trade. A take profit level is a predefined exit level used to secure gains if the market moves in favor of the trade. Professional stop placement is based on trade invalidation, not random distance — if the trade idea becomes technically invalid at a certain level, that level becomes the logical stop area. Take profit planning should be based on realistic market structure, liquidity zones, resistance-support areas, volatility, and risk-reward ratio.' },
          { type: 'heading', text: 'Professional Application' },
          { type: 'paragraph', text: 'Professional traders plan exits before entry. This includes defining the invalidation point, target area, position size, maximum risk, and possible trade management method. Some traders use fixed targets, while others use trailing stops, partial exits, or structure-based profit-taking. A high-quality trade plan answers three questions: where to enter, where the idea is wrong, and where profit should reasonably be taken.' },
          { type: 'heading', text: 'Common Misinterpretations' },
          { type: 'paragraph', text: 'A common mistake is moving stop-losses emotionally after price moves against the trade. Another mistake is taking profits too early out of fear while allowing losses to grow. Poor exit planning can damage even a strong entry strategy.' },
          { type: 'callout', text: '<strong>Professional Summary:</strong> Stop loss and take profit planning transform a trade from a prediction into a controlled risk decision. They are essential for consistency, capital protection, and professional execution.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This material is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any financial instrument. Stop-loss and take-profit orders do not guarantee execution at desired prices and may be affected by gaps, slippage, volatility, and liquidity. Conduct independent analysis and consult qualified professionals before making financial decisions.' },
        ]
      },
    ]
  },

  // ── FUNDAMENTAL ANALYSIS ───────────────────────────────────────────────────
  {
    id: 'fundamental-analysis', icon: '📊', title: 'Fundamental Analysis',
    desc: 'Company valuation, financial statements, EPS, P/E ratio, macroeconomic data, and asset-based analysis.',
    topics: [
      { id: 'what-is-fa', title: 'What is Fundamental Analysis?', level: 'Beginner', summary: 'The practice of evaluating an asset based on its intrinsic value.',
        content: [
          { type: 'image', src: 'images/SNRFA001.jpg', alt: 'What is Fundamental Analysis' },
          { type: 'paragraph', text: 'Fundamental analysis is a structured method of evaluating the real economic value, financial strength, operating performance, and future potential of a company, asset, or market. Unlike short-term price speculation, fundamental analysis focuses on the underlying factors that may influence long-term value.' },
          { type: 'heading', text: 'What It Covers' },
          { type: 'paragraph', text: 'In the stock market, fundamental analysis studies a company\'s financial statements, revenue growth, profitability, debt levels, cash flow, management quality, industry position, competitive advantage, dividend policy, and valuation. The objective is to determine whether a security is fairly priced, undervalued, or overvalued compared to its intrinsic value.' },
          { type: 'heading', text: 'A Multi-Layer Approach' },
          { type: 'paragraph', text: 'At a professional level, fundamental analysis connects multiple layers of information: company performance, sector conditions, macroeconomic environment, interest rates, inflation, regulatory changes, business cycles, and investor sentiment. A strong company may still be a poor investment if purchased at an unreasonable valuation, while a temporarily weak company may become attractive if the market price already reflects excessive pessimism.' },
          { type: 'heading', text: 'Who Uses It and Its Limits' },
          { type: 'paragraph', text: 'Fundamental analysis is widely used by long-term investors, portfolio managers, equity analysts, and institutional investors. However, it is not a guarantee of profit. Markets can remain irrational for extended periods, financial forecasts can be wrong, and unexpected events can change business performance. Professional investors combine it with valuation discipline, risk management, and market awareness.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Fundamental analysis is the process of evaluating the underlying economic value and financial quality of an asset to support informed investment decisions.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, hold, or trade any financial instrument. Fundamental analysis involves assumptions and estimates that may be incomplete or inaccurate. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'why-fa-matters', title: 'Why Fundamental Analysis Matters', level: 'Beginner', summary: 'How FA helps investors find undervalued opportunities.',
        content: [
          { type: 'image', src: 'images/SNRFA002.jpg', alt: 'Why Fundamental Analysis Matters' },
          { type: 'paragraph', text: 'Fundamental analysis matters because it helps investors understand the difference between market price and underlying value. In financial markets, price can move due to emotion, speculation, liquidity, news, short-term sentiment, or temporary market pressure. Fundamental analysis helps determine whether those price movements are supported by real business performance and economic value.' },
          { type: 'heading', text: 'Key Questions It Answers' },
          { type: 'paragraph', text: 'For investors, fundamental analysis provides a framework for identifying strong companies, avoiding weak businesses, and building long-term conviction. It helps answer critical questions: Is the company profitable? Is revenue growing? Is debt manageable? Is cash flow strong? Is the business model sustainable? Is the stock price justified by earnings and future growth?' },
          { type: 'heading', text: 'Why It Matters During Market Moves' },
          { type: 'paragraph', text: 'Without fundamental analysis, investors may rely only on price movement, rumors, or hype — which can lead to poor decisions during speculative phases. Fundamental analysis is especially important during market corrections. When prices fall, investors with fundamental knowledge can distinguish between temporary weakness and genuine business deterioration, allowing more disciplined decision-making.' },
          { type: 'heading', text: 'Capital Allocation Tool' },
          { type: 'paragraph', text: 'Professional investors use fundamental analysis for capital allocation. They compare companies across sectors, assess return potential, analyze downside risk, and determine whether a stock fits a portfolio objective. It also helps evaluate dividend sustainability, earnings quality, financial stability, and long-term competitive strength.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Fundamental analysis matters because it connects investment decisions to business reality, valuation logic, and long-term financial performance rather than short-term market noise.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or hold any financial instrument. Fundamental analysis may reduce uncertainty but cannot eliminate market risk. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'company-financials', title: 'Understanding Company Financial Statements', level: 'Beginner', summary: 'The three core financial documents every investor should read.',
        content: [
          { type: 'image', src: 'images/SNRFA003.jpg', alt: 'Understanding Company Financial Statements' },
          { type: 'paragraph', text: 'Company financial statements are formal reports that present a business\'s financial performance, financial position, and cash movement over a specific period. They are the foundation of fundamental analysis because they provide measurable evidence of how a company earns money, uses capital, manages debt, and generates cash.' },
          { type: 'heading', text: 'The Three Core Statements' },
          { type: 'paragraph', text: 'The three core financial statements are the income statement, balance sheet, and cash flow statement. The income statement shows revenue, expenses, and profit. The balance sheet shows assets, liabilities, and shareholders\' equity. The cash flow statement shows actual cash generated and used by the business.' },
          { type: 'heading', text: 'Why You Must Connect All Three' },
          { type: 'paragraph', text: 'Professional analysis requires connecting all three statements. A company may report strong profits but weak cash flow. Another may show high assets but excessive debt. A complete analysis examines whether profits are supported by cash generation, whether growth is funded sustainably, and whether the financial structure is healthy.' },
          { type: 'heading', text: 'Beyond the Headline Numbers' },
          { type: 'paragraph', text: 'Financial statements also help calculate key ratios such as EPS, P/E ratio, debt-to-equity, return on equity, free cash flow, profit margins, and dividend payout ratio. Investors should also read notes to financial statements, auditor reports, management discussions, and segment disclosures — important risks are often found outside the headline numbers.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Financial statements provide the factual foundation for evaluating business quality, profitability, liquidity, solvency, and shareholder value creation.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, accounting, or investment advice. Financial statements may include estimates, accounting judgments, and reporting limitations. Conduct your own research and consult qualified professionals before making decisions.' },
        ]
      },
      { id: 'balance-sheet', title: 'Balance Sheet Explained', level: 'Beginner', summary: 'Assets, liabilities, and equity — reading a company\'s balance sheet.',
        content: [
          { type: 'image', src: 'images/SNRFA004.jpg', alt: 'Balance Sheet Explained' },
          { type: 'paragraph', text: 'The balance sheet is a financial statement that shows a company\'s financial position at a specific point in time. It presents what the company owns, what it owes, and what belongs to shareholders.' },
          { type: 'heading', text: 'The Accounting Equation' },
          { type: 'paragraph', text: 'The balance sheet is built around the accounting equation: Assets = Liabilities + Shareholders\' Equity. Assets include cash, inventory, receivables, property, equipment, investments, and intangible assets. Liabilities include loans, payables, lease obligations, and other financial obligations. Shareholders\' equity represents the residual ownership value after liabilities are deducted from assets.' },
          { type: 'heading', text: 'What to Analyze' },
          { type: 'paragraph', text: 'From a fundamental analysis perspective, the balance sheet helps assess financial strength and risk. A company with strong cash reserves, manageable debt, and quality assets may be more resilient during difficult conditions. A company with excessive borrowing, weak liquidity, or declining asset quality may face higher financial stress.' },
          { type: 'heading', text: 'Quality Over Size' },
          { type: 'paragraph', text: 'Important areas to analyze include current assets versus current liabilities, debt maturity, working capital, retained earnings, book value, inventory levels, receivables quality, and leverage. A balance sheet should not be reviewed only for size but also for quality. Large assets may not be valuable if they are difficult to convert to cash or are overstated. Professional investors use the balance sheet to understand whether a company can survive downturns, fund growth, and pay dividends.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> The balance sheet measures financial position, capital structure, liquidity, solvency, and the quality of resources available to a company.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, accounting, or investment advice. Balance sheet analysis may be affected by accounting policies, asset valuation methods, and disclosure limitations. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'income-statement', title: 'Income Statement Explained', level: 'Beginner', summary: 'Revenue, expenses, and profit on the income statement.',
        content: [
          { type: 'image', src: 'images/SNRFA005.jpg', alt: 'Income Statement Explained' },
          { type: 'paragraph', text: 'The income statement shows a company\'s financial performance over a specific period, usually quarterly, semi-annually, or annually. It explains how much revenue the company generated, what costs it incurred, and how much profit remained after expenses.' },
          { type: 'heading', text: 'Structure of the Income Statement' },
          { type: 'paragraph', text: 'The income statement typically begins with revenue, then subtracts cost of goods sold to calculate gross profit. Operating expenses are then deducted to arrive at operating profit. After accounting for interest, taxes, and other non-operating items, the final result is net income. Revenue growth indicates business expansion, while gross margin and operating margin reveal pricing power and cost control.' },
          { type: 'heading', text: 'Profit Quality Matters' },
          { type: 'paragraph', text: 'A company may report high earnings due to one-time gains, accounting adjustments, asset sales, or temporary factors. Professional analysts separate recurring operating performance from unusual items to understand sustainable profitability. The income statement is most useful when analyzed as a trend — a single year of profit may not be enough. Investors should analyze whether revenue, margins, and earnings are improving consistently over multiple periods.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> The income statement evaluates a company\'s ability to generate revenue, control costs, produce profit, and improve operating performance over time.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, accounting, or investment advice. Income statement analysis may be affected by accounting estimates, non-recurring items, and management assumptions. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'cash-flow-statement', title: 'Cash Flow Statement Explained', level: 'Beginner', summary: 'How cash moves in and out of a business.',
        content: [
          { type: 'image', src: 'images/SNRFA006.jpg', alt: 'Cash Flow Statement Explained' },
          { type: 'paragraph', text: 'The cash flow statement shows how cash moves in and out of a company during a specific period. It is one of the most important financial statements because cash flow reveals whether a business is actually generating usable money, not just accounting profit.' },
          { type: 'heading', text: 'Three Sections' },
          { type: 'paragraph', text: 'The cash flow statement is divided into three sections: operating activities, investing activities, and financing activities. Operating cash flow shows cash generated from the company\'s core business. Investing cash flow shows cash used for assets, acquisitions, or investments. Financing cash flow shows cash raised from or returned to lenders and shareholders.' },
          { type: 'heading', text: 'Why Operating Cash Flow is Critical' },
          { type: 'paragraph', text: 'Operating cash flow is especially important because it indicates whether the core business can generate cash independently. A company with strong accounting profit but weak operating cash flow may have poor earnings quality, delayed collections, or working capital pressure. Free cash flow is derived by subtracting capital expenditures from operating cash flow, showing how much cash remains after the business reinvests in itself.' },
          { type: 'paragraph', text: 'Professional investors pay close attention to cash flow because companies need cash to pay debt, distribute dividends, repurchase shares, expand operations, and survive downturns. Profit can be adjusted through accounting methods, but cash flow is harder to manipulate over the long term.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> The cash flow statement evaluates the real cash generation capacity of a business and helps determine earnings quality, financial flexibility, and sustainability.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, accounting, or investment advice. Cash flow analysis may be affected by working capital timing, capital expenditure cycles, and accounting classification. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'revenue-profit-income', title: 'Revenue, Profit, and Net Income', level: 'Beginner', summary: 'The difference between top-line and bottom-line numbers.',
        content: [
          { type: 'image', src: 'images/SNRFA007.jpg', alt: 'Revenue Profit and Net Income' },
          { type: 'paragraph', text: 'Revenue, profit, and net income are core financial concepts used to evaluate company performance. Although these terms are connected, they represent different stages of business results.' },
          { type: 'heading', text: 'Revenue — The Top Line' },
          { type: 'paragraph', text: 'Revenue is the total amount a company earns from selling goods or services before expenses are deducted. It is called the top line because it appears near the top of the income statement. Revenue growth can indicate business expansion, stronger demand, pricing power, or market share gains.' },
          { type: 'heading', text: 'Profit — Multiple Levels' },
          { type: 'paragraph', text: 'Profit is what remains after certain costs are deducted from revenue. There are different levels of profit: gross profit shows profitability after direct production costs; operating profit shows profitability after operating expenses; net income shows the final profit after all expenses, interest, and taxes. Net income is called the bottom line because it appears near the bottom of the income statement.' },
          { type: 'heading', text: 'Why Margins Matter' },
          { type: 'paragraph', text: 'A company with high revenue but low profit may have weak margins, high costs, or inefficient operations. A company with moderate revenue but strong profit margins may be more efficient and financially attractive. Professional analysis focuses not only on growth but also on profitability quality. Investors should examine whether revenue growth is sustainable, whether margins are improving, and whether net income is supported by cash flow.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Revenue measures business activity, profit measures operating effectiveness, and net income measures final accounting earnings attributable to the company after expenses.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, accounting, or investment advice. Financial figures may be affected by accounting policies, one-time items, and business cycles. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'eps-explained', title: 'EPS: Earnings Per Share Explained', level: 'Beginner', summary: 'What EPS reveals about a company\'s profitability per share.',
        content: [
          { type: 'image', src: 'images/SNRFA008.jpg', alt: 'EPS Earnings Per Share Explained' },
          { type: 'paragraph', text: 'Earnings Per Share, commonly known as EPS, measures how much profit a company generates for each outstanding share of common stock. It is one of the most widely used indicators of profitability and is central to equity valuation.' },
          { type: 'heading', text: 'The Formula' },
          { type: 'paragraph', text: 'EPS = Net Income Available to Common Shareholders ÷ Weighted Average Shares Outstanding. If net income increases while the number of shares remains stable, EPS usually improves. If a company issues more shares, EPS may decline due to dilution unless profits grow enough to offset the increase.' },
          { type: 'heading', text: 'Basic vs Diluted EPS' },
          { type: 'paragraph', text: 'Basic EPS uses the existing share count, while diluted EPS includes the potential impact of stock options, convertible securities, and other instruments that could increase the share count. Diluted EPS is generally more conservative and widely used in professional analysis. Companies with consistent EPS growth often attract investor attention because earnings growth can support long-term share price appreciation.' },
          { type: 'heading', text: 'Analyzing Earnings Quality' },
          { type: 'paragraph', text: 'EPS must be analyzed carefully. Share buybacks can increase EPS even if total net income does not grow. One-time gains can temporarily inflate EPS. Professional analysts evaluate earnings quality, recurring profitability, cash flow support, and dilution risk before relying on EPS as a valuation input.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> EPS measures shareholder-level profitability and is a key input in valuation, earnings growth analysis, and market expectations.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, accounting, or investment advice. EPS can be affected by share buybacks, dilution, one-time gains, and non-cash items. EPS growth does not guarantee future share price appreciation. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'pe-ratio-explained', title: 'P/E Ratio Explained', level: 'Beginner', summary: 'How to use the Price-to-Earnings ratio to value stocks.',
        content: [
          { type: 'image', src: 'images/SNRFA009.jpg', alt: 'P/E Ratio Explained' },
          { type: 'paragraph', text: 'The Price-to-Earnings ratio, or P/E ratio, is a valuation metric that compares a company\'s share price to its earnings per share. It shows how much investors are willing to pay for each unit of earnings.' },
          { type: 'heading', text: 'The Formula' },
          { type: 'paragraph', text: 'P/E Ratio = Market Price Per Share ÷ Earnings Per Share. A P/E ratio of 15 means investors are paying 15 times the company\'s annual earnings per share. A high P/E may indicate strong growth expectations, superior business quality, or overvaluation. A low P/E may indicate undervaluation, weak growth expectations, or declining earnings.' },
          { type: 'heading', text: 'Context is Everything' },
          { type: 'paragraph', text: 'Professional use of P/E requires context. A technology company, bank, utility, and cyclical commodity company may naturally trade at different P/E levels. Therefore, P/E should be compared with industry peers, historical averages, expected earnings growth, interest rates, and business quality. There is also trailing P/E (using past earnings) and forward P/E (using expected future earnings). Forward P/E can be useful but depends on forecasts which may change.' },
          { type: 'paragraph', text: 'The P/E ratio should never be used alone. Investors should also examine earnings quality, debt levels, cash flow, return on equity, growth rate, and macroeconomic conditions.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> The P/E ratio measures how the market values a company\'s earnings, but its meaning depends on growth expectations, sector norms, earnings quality, and valuation context.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, accounting, or investment advice. The P/E ratio may be misleading if earnings are cyclical, negative, or affected by accounting adjustments. A low P/E does not guarantee undervaluation. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'book-value-pb', title: 'Book Value and Price-to-Book Ratio', level: 'Intermediate', summary: 'Measuring what a company is worth on paper vs its market price.',
        content: [
          { type: 'image', src: 'images/SNRFA010.jpg', alt: 'Book Value and Price-to-Book Ratio' },
          { type: 'paragraph', text: 'Book value represents the accounting value of shareholders\' equity on a company\'s balance sheet. It is calculated as total assets minus total liabilities. On a per-share basis, book value indicates the net asset value attributable to each share.' },
          { type: 'heading', text: 'The P/B Ratio' },
          { type: 'paragraph', text: 'P/B Ratio = Market Price Per Share ÷ Book Value Per Share. A P/B ratio below 1 may suggest the market price is lower than accounting net assets. However, this does not automatically mean undervaluation — the assets may be poor quality, overstated, illiquid, or unable to generate strong returns. A high P/B may indicate strong profitability, valuable intangibles, or high return on equity.' },
          { type: 'heading', text: 'When P/B is Most Useful' },
          { type: 'paragraph', text: 'P/B ratio is often more useful for banks, insurance companies, financial institutions, and asset-heavy businesses. It may be less useful for technology, service, or brand-driven companies where intangible assets and intellectual property are more important. Professional investors use P/B alongside return on equity — a high P/B may be justified if the company generates superior returns; a low P/B may be a warning sign if returns are weak.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Book value measures accounting net assets, while the P/B ratio shows how the market values those assets relative to reported equity.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, accounting, or investment advice. Book value may not reflect real market value or future earning potential. P/B ratio should not be used in isolation. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'dividend-payout', title: 'Dividend Yield and Payout Ratio', level: 'Beginner', summary: 'Evaluating how much a company returns to shareholders.',
        content: [
          { type: 'image', src: 'images/SNRFA011.jpg', alt: 'Dividend Yield and Payout Ratio' },
          { type: 'paragraph', text: 'Dividend yield and payout ratio are important metrics for evaluating dividend-paying companies. They help investors understand both the income return and the sustainability of dividend payments.' },
          { type: 'heading', text: 'Dividend Yield' },
          { type: 'paragraph', text: 'Dividend Yield = Annual Dividend Per Share ÷ Market Price Per Share × 100. A higher dividend yield may appear attractive for income-focused investors. However, high yield can also indicate risk if the share price has fallen due to weak business performance — this is known as a dividend trap.' },
          { type: 'heading', text: 'Payout Ratio' },
          { type: 'paragraph', text: 'Payout Ratio = Dividend Per Share ÷ Earnings Per Share × 100. A moderate payout ratio may indicate the company is distributing profits while retaining enough earnings for reinvestment. A very high payout ratio may suggest dividends are less sustainable, especially if earnings decline.' },
          { type: 'heading', text: 'Analyzing Sustainability' },
          { type: 'paragraph', text: 'Professional dividend analysis focuses on sustainability, not only yield. Investors should study earnings stability, free cash flow, debt levels, capital expenditure needs, and dividend history. A dividend supported by recurring cash flow is generally stronger than one funded through borrowing. Dividends are never guaranteed — boards can reduce, suspend, or cancel them based on business conditions.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Dividend yield measures income return, while payout ratio evaluates how much of earnings are distributed to shareholders and whether dividends may be sustainable.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial or investment advice. Dividends are not guaranteed and may be reduced or cancelled. High dividend yield may indicate elevated risk. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'debt-to-equity', title: 'Debt-to-Equity Ratio', level: 'Intermediate', summary: 'Measuring financial leverage and balance sheet risk.',
        content: [
          { type: 'image', src: 'images/SNRFA012.jpg', alt: 'Debt-to-Equity Ratio' },
          { type: 'paragraph', text: 'The debt-to-equity ratio measures the relationship between a company\'s debt and shareholders\' equity. It helps investors understand how much financial leverage a company uses to fund its operations and growth.' },
          { type: 'heading', text: 'The Formula' },
          { type: 'paragraph', text: 'Debt-to-Equity Ratio = Total Debt ÷ Shareholders\' Equity. A high ratio may indicate that a company relies heavily on borrowing, which can increase risk during economic downturns, rising interest rates, or declining revenue. A low ratio may indicate a more conservative capital structure, though very low debt is not always better — some companies use debt efficiently to fund profitable expansion.' },
          { type: 'heading', text: 'Industry Context Matters' },
          { type: 'paragraph', text: 'The appropriate level of debt varies by industry. Utilities, banks, real estate companies, and infrastructure businesses may naturally carry more debt than technology or service companies. Therefore, debt-to-equity should always be compared with industry peers and business stability.' },
          { type: 'paragraph', text: 'Professional analysis also considers interest coverage, debt maturity, cash reserves, cash flow generation, and whether debt is fixed-rate or floating-rate. A company with strong cash flow may manage debt better than a company with volatile earnings.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> The debt-to-equity ratio evaluates financial leverage and capital structure risk by comparing borrowed funds with shareholder capital.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, accounting, or investment advice. Debt ratios may vary by industry and accounting treatment. A high or low ratio alone does not determine investment quality. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'roe-roa', title: 'Return on Equity and Return on Assets', level: 'Intermediate', summary: 'Efficiency ratios that reveal how well a company uses its resources.',
        content: [
          { type: 'image', src: 'images/SNRFA013.jpg', alt: 'Return on Equity and Return on Assets' },
          { type: 'paragraph', text: 'Return on Equity and Return on Assets are profitability ratios used to evaluate how efficiently a company generates profit from its capital base.' },
          { type: 'heading', text: 'Return on Equity (ROE)' },
          { type: 'paragraph', text: 'ROE = Net Income ÷ Shareholders\' Equity × 100. A high ROE may indicate strong profitability, efficient capital use, pricing power, or competitive advantage. However, ROE can be inflated by high debt because debt reduces equity. Therefore, ROE should always be analyzed alongside leverage levels.' },
          { type: 'heading', text: 'Return on Assets (ROA)' },
          { type: 'paragraph', text: 'ROA = Net Income ÷ Total Assets × 100. ROA measures how efficiently a company uses its total assets to generate profit. It is especially important for asset-heavy industries such as banking, manufacturing, logistics, utilities, and real estate.' },
          { type: 'heading', text: 'Combining the Two' },
          { type: 'paragraph', text: 'Professional analysts compare ROE and ROA over time and against industry peers. A company that consistently generates high returns without excessive leverage may have strong business quality. Declining returns may indicate margin pressure, poor capital allocation, or rising competition. ROE and ROA are more meaningful when combined with profit margins, asset turnover, debt levels, and cash flow.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> ROE measures profit generation from shareholder capital, while ROA measures profit generation from total assets. Together, they help assess efficiency, profitability, and business quality.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, accounting, or investment advice. ROE and ROA may be affected by leverage, accounting policies, and one-time income. High returns do not guarantee future performance. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'free-cash-flow', title: 'Free Cash Flow Explained', level: 'Intermediate', summary: 'Why FCF is often more telling than reported profit.',
        content: [
          { type: 'image', src: 'images/SNRFA014.jpg', alt: 'Free Cash Flow Explained' },
          { type: 'paragraph', text: 'Free Cash Flow, often called FCF, represents the cash a company generates after covering operating expenses and necessary capital expenditures. It is one of the most important indicators of financial strength because it shows how much cash remains available for debt repayment, dividends, share buybacks, acquisitions, or reinvestment.' },
          { type: 'heading', text: 'The Formula' },
          { type: 'paragraph', text: 'Free Cash Flow = Operating Cash Flow − Capital Expenditures. Positive free cash flow indicates the company is generating more cash than it needs to maintain or expand operations. A company may report net income but still struggle if customers delay payments, inventory builds up, or capital expenditures consume cash.' },
          { type: 'heading', text: 'Why FCF Matters' },
          { type: 'paragraph', text: 'Professional investors value free cash flow because it is harder to manipulate than accounting profit over the long term. Free cash flow is especially important for mature companies, dividend-paying businesses, and companies with large capital expenditure requirements. It helps determine whether dividends are sustainable, debt can be serviced, and growth can be funded internally.' },
          { type: 'paragraph', text: 'However, negative free cash flow is not always bad. A growing company may invest heavily in expansion, reducing short-term FCF but creating long-term value if investments generate strong returns.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Free cash flow measures the cash available after essential business reinvestment and is a key indicator of financial flexibility, dividend capacity, and long-term business quality.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, accounting, or investment advice. Free cash flow may vary due to working capital changes, capital expenditure cycles, and business strategy. Positive FCF does not guarantee investment success. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'market-cap-explained', title: 'Market Capitalization Explained', level: 'Beginner', summary: 'Understanding the total market value of a company.',
        content: [
          { type: 'image', src: 'images/SNRFA015.jpg', alt: 'Market Capitalization Explained' },
          { type: 'paragraph', text: 'Market capitalization represents the total market value of a publicly listed company\'s outstanding shares. It is calculated by multiplying the current share price by the total number of outstanding shares.' },
          { type: 'heading', text: 'The Formula and Categories' },
          { type: 'paragraph', text: 'Market Capitalization = Share Price × Outstanding Shares. Companies are commonly grouped as large-cap, mid-cap, small-cap, or micro-cap. Large-cap companies are often more established, liquid, and widely followed. Mid-cap companies may offer a balance of growth and maturity. Small-cap companies may offer higher growth potential but usually involve greater volatility, lower liquidity, and higher business risk.' },
          { type: 'heading', text: 'What Market Cap Does Not Tell You' },
          { type: 'paragraph', text: 'Market cap does not determine whether a company is expensive or cheap. A large company can be overvalued while a small company can be undervalued or highly risky. Valuation requires comparison with earnings, cash flow, assets, growth prospects, and business quality. Professional investors use market capitalization for portfolio construction, index analysis, liquidity assessment, and risk classification.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Market capitalization measures the market value of a company\'s equity and helps classify company size, liquidity, risk profile, and portfolio relevance.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial or investment advice. Market cap does not represent intrinsic value. Large-cap stocks may decline significantly and small-cap stocks may involve elevated volatility. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'sector-industry', title: 'Sector and Industry Analysis', level: 'Intermediate', summary: 'Evaluating companies within the context of their sector.',
        content: [
          { type: 'image', src: 'images/SNRFA016.jpg', alt: 'Sector and Industry Analysis' },
          { type: 'paragraph', text: 'Sector and industry analysis is the process of evaluating the broader business environment in which a company operates. A company\'s performance is shaped not only by internal management or financials but also by industry growth, competition, regulation, technology, consumer demand, and macroeconomic conditions.' },
          { type: 'heading', text: 'Sector vs Industry' },
          { type: 'paragraph', text: 'A sector is a broad category such as banking, energy, technology, healthcare, consumer goods, or industrials. An industry is a more specific group within a sector. For example, within the energy sector, there may be oil exploration, refining, gas distribution, and renewable energy industries.' },
          { type: 'heading', text: 'Cyclical vs Defensive Sectors' },
          { type: 'paragraph', text: 'Professional investors analyze sectors to understand where capital is flowing, which industries are expanding, and which are under pressure. Some sectors perform better during economic expansion, while others may be more defensive during downturns. Consumer staples and utilities may be relatively defensive, while cyclical sectors may be more sensitive to economic growth.' },
          { type: 'heading', text: 'Industry Analysis Factors' },
          { type: 'paragraph', text: 'Industry analysis includes market size, demand trends, pricing power, regulation, cost structure, competitive intensity, technological disruption, and barriers to entry. Sector rotation is also important — investors often move capital between sectors based on interest rates, inflation, commodity prices, economic cycles, and policy changes.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Sector and industry analysis evaluates the external business environment to understand growth potential, competitive pressure, regulatory risk, and market cycle positioning.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial or investment advice. Sector and industry conditions can change due to economic cycles, regulation, disruption, and investor sentiment. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'economic-moat', title: 'Economic Moat and Competitive Advantage', level: 'Intermediate', summary: 'What makes a business durable and hard to compete with.',
        content: [
          { type: 'image', src: 'images/SNRFA017.jpg', alt: 'Economic Moat and Competitive Advantage' },
          { type: 'paragraph', text: 'An economic moat refers to a company\'s ability to protect its profits, market share, and competitive position from rivals over time. The term describes a sustainable competitive advantage that allows a business to defend itself against competition.' },
          { type: 'heading', text: 'Types of Moats' },
          { type: 'paragraph', text: 'Companies with strong moats often have pricing power, customer loyalty, cost advantages, network effects, strong brands, regulatory protection, intellectual property, scale advantages, or high switching costs. For example, a company with a strong brand may charge premium prices. A company with network effects becomes more valuable as more users join its platform. A company with low production costs may survive price competition better than weaker rivals.' },
          { type: 'heading', text: 'Why Moats Matter for Investors' },
          { type: 'paragraph', text: 'Economic moats matter because long-term shareholder value depends not only on current profits but on the ability to sustain those profits. Professional investors look for evidence of a moat in financial results: high and consistent return on equity, stable margins, recurring revenue, strong cash flow, and market share leadership.' },
          { type: 'paragraph', text: 'However, moats can weaken due to disruption, regulation, poor management, or changing consumer behavior. A moat that exists today may not be as strong tomorrow, which is why ongoing analysis is necessary.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> An economic moat is a durable competitive advantage that helps a company protect profitability, market position, and long-term shareholder value.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial or investment advice. Competitive advantage is difficult to measure and may weaken over time. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'growth-vs-value', title: 'Growth Stocks vs Value Stocks', level: 'Intermediate', summary: 'Two contrasting investment philosophies explained.',
        content: [
          { type: 'image', src: 'images/SNRFA018.jpg', alt: 'Growth Stocks vs Value Stocks' },
          { type: 'paragraph', text: 'Growth stocks and value stocks represent two major investment styles. Each has different characteristics, valuation logic, risk profile, and market behavior.' },
          { type: 'heading', text: 'Growth Stocks' },
          { type: 'paragraph', text: 'Growth stocks are companies expected to increase revenue, earnings, or cash flow faster than the broader market. These companies often reinvest profits into expansion rather than paying high dividends. Growth stocks may trade at higher valuation multiples because investors expect strong future performance. Growth investing focuses on future expansion, innovation, market share gains, and earnings acceleration.' },
          { type: 'heading', text: 'Value Stocks' },
          { type: 'paragraph', text: 'Value stocks are companies that appear to trade below their estimated intrinsic value based on earnings, assets, dividends, cash flow, or book value. These stocks may be overlooked, temporarily unpopular, or priced pessimistically. Value investing focuses on price discipline, margin of safety, asset value, and market mispricing.' },
          { type: 'heading', text: 'Neither is Always Right' },
          { type: 'paragraph', text: 'Both styles can perform well in different market conditions. Growth stocks may perform better when interest rates are low and investors are willing to pay for future earnings. Value stocks may perform better when markets favor current earnings and lower valuations. Professional investors do not assume growth is always expensive or value is always cheap. A growth stock may be attractive if future earnings justify the valuation, while a value stock may be a value trap if the business is permanently declining.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Growth stocks offer higher expected expansion, while value stocks offer potential mispricing opportunities based on current fundamentals and valuation discipline.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial or investment advice. Investment styles can underperform for extended periods. Growth expectations may fail, and value stocks may remain undervalued or deteriorate. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'undervalued-overvalued', title: 'Undervalued vs Overvalued Stocks', level: 'Intermediate', summary: 'How to determine if a stock is priced fairly.',
        content: [
          { type: 'image', src: 'images/SNRFA019.jpg', alt: 'Undervalued vs Overvalued Stocks' },
          { type: 'paragraph', text: 'An undervalued stock is one that appears to trade below its estimated intrinsic value. An overvalued stock is one that appears to trade above its estimated intrinsic value. These concepts are central to fundamental analysis and valuation.' },
          { type: 'heading', text: 'Intrinsic Value' },
          { type: 'paragraph', text: 'Intrinsic value is an estimate of what a company is worth based on earnings, cash flow, assets, growth potential, competitive position, and risk. Since intrinsic value is an estimate, different analysts may reach different conclusions using different assumptions.' },
          { type: 'heading', text: 'Why Stocks Become Undervalued or Overvalued' },
          { type: 'paragraph', text: 'A stock may be undervalued because the market is overly pessimistic, the company is temporarily misunderstood, earnings are recovering, or assets are not fully recognized. A stock may be overvalued when market expectations become too optimistic, valuation multiples rise beyond reasonable levels, or price increases faster than earnings growth.' },
          { type: 'heading', text: 'Valuation Methods' },
          { type: 'paragraph', text: 'Professional valuation requires comparing price with earnings, cash flow, book value, growth rate, sector multiples, interest rates, and risk factors. Analysts may use methods such as discounted cash flow, relative valuation, asset-based valuation, and dividend models. A low price alone does not mean undervaluation — the company may be cheap for valid reasons such as declining fundamentals.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Undervaluation and overvaluation compare market price with estimated intrinsic value, but the accuracy depends on assumptions, business quality, and future performance.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial or investment advice. Valuation is based on assumptions that may be incorrect. An undervalued stock may decline further, and an overvalued stock may continue rising. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'interest-rates-markets', title: 'Interest Rates and Their Impact on Markets', level: 'Intermediate', summary: 'Why central bank decisions move stocks, bonds, and currencies.',
        content: [
          { type: 'image', src: 'images/SNRFA020.jpg', alt: 'Interest Rates and Their Impact on Markets' },
          { type: 'paragraph', text: 'Interest rates are one of the most important macroeconomic factors affecting financial markets. They influence borrowing costs, business investment, consumer spending, asset valuations, currency strength, bond yields, and investor risk appetite.' },
          { type: 'heading', text: 'When Rates Rise' },
          { type: 'paragraph', text: 'When interest rates rise, borrowing becomes more expensive for companies and consumers. This can reduce corporate profits, slow economic activity, and pressure stock valuations. Higher rates also make fixed-income instruments more attractive, which may reduce demand for riskier assets such as equities.' },
          { type: 'heading', text: 'When Rates Fall' },
          { type: 'paragraph', text: 'When interest rates fall, borrowing becomes cheaper. This can support business expansion, consumer spending, and higher asset valuations. Lower rates may encourage investors to seek higher returns in stocks, real estate, commodities, or other risk assets.' },
          { type: 'heading', text: 'Impact on Valuation and Other Assets' },
          { type: 'paragraph', text: 'Interest rates affect valuation through discount rates. When discount rates rise, the present value of future cash flows may decline — this is why high-growth companies can be sensitive to rate changes. Rates also influence currencies and commodities: higher rates may strengthen a currency if they attract capital inflows, while gold may face pressure when real interest rates rise because gold does not pay interest.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Interest rates influence the cost of capital, valuation multiples, liquidity conditions, investor behavior, and the relative attractiveness of asset classes.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, macroeconomic, or investment advice. Interest rate effects may vary by market, sector, and economic environment. Central bank decisions and market reactions are uncertain. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'inflation-investments', title: 'Inflation and Its Impact on Investments', level: 'Intermediate', summary: 'How rising prices erode or shift investment returns.',
        content: [
          { type: 'image', src: 'images/SNRFA021.jpg', alt: 'Inflation and Its Impact on Investments' },
          { type: 'paragraph', text: 'Inflation refers to a general rise in prices over time, reducing the purchasing power of money. For investors, inflation is important because it affects interest rates, corporate costs, consumer demand, asset valuations, and real investment returns.' },
          { type: 'heading', text: 'How Inflation Affects Businesses' },
          { type: 'paragraph', text: 'High inflation can create pressure on businesses and consumers. Companies may face higher costs for raw materials, wages, transportation, and financing. If they cannot pass those costs to customers, profit margins may decline. Inflation also affects interest rates — central banks may raise rates to control inflation, which can reduce stock valuations and increase borrowing costs.' },
          { type: 'heading', text: 'How Different Assets Respond' },
          { type: 'paragraph', text: 'Different investments respond differently to inflation. Companies with pricing power may protect margins better. Commodities may benefit during inflationary periods as physical inputs. Bonds may suffer when inflation rises because fixed payments lose real value. Gold may attract demand as an inflation-sensitive asset, though its performance also depends on interest rates and currency strength.' },
          { type: 'heading', text: 'Real Returns' },
          { type: 'paragraph', text: 'Professional investors focus on real returns, meaning returns after adjusting for inflation. A portfolio may show positive nominal returns but still lose purchasing power if inflation is higher.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Inflation affects investments by changing purchasing power, interest rates, business costs, consumer behavior, and real asset returns.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, macroeconomic, or investment advice. Inflation effects can vary across sectors, countries, and asset classes. No inflation-based strategy guarantees protection or profit. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'gdp-employment-sentiment', title: 'GDP, Employment Data and Market Sentiment', level: 'Intermediate', summary: 'Key macroeconomic indicators and how markets respond.',
        content: [
          { type: 'image', src: 'images/SNRFA022.jpg', alt: 'GDP Employment Data and Market Sentiment' },
          { type: 'paragraph', text: 'GDP, employment data, and market sentiment are key macroeconomic indicators used in fundamental analysis. They help investors understand economic strength, consumer behavior, corporate earnings potential, and risk appetite.' },
          { type: 'heading', text: 'GDP' },
          { type: 'paragraph', text: 'Gross Domestic Product, or GDP, measures the total value of goods and services produced by an economy. Strong GDP growth may indicate business expansion, rising demand, and supportive conditions for corporate earnings. Weak GDP growth may signal economic slowdown, lower demand, and pressure on profits.' },
          { type: 'heading', text: 'Employment Data' },
          { type: 'paragraph', text: 'Employment data measures labor market strength. Strong employment can support consumer spending, income growth, and economic confidence. However, very strong employment may also contribute to inflation pressure, which can influence central bank policy. Weak employment may signal economic stress but may also increase expectations of monetary support.' },
          { type: 'heading', text: 'Market Sentiment and Expectations' },
          { type: 'paragraph', text: 'Market sentiment reflects investor psychology. Even when economic data is strong, markets may decline if investors fear inflation, higher rates, or slowing future growth. Professional analysis connects economic data with market expectations. The actual number matters, but the difference between actual results and expectations often drives market reaction — markets are forward-looking and may respond more to future implications than current data.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> GDP, employment data, and sentiment help assess economic momentum, earnings outlook, policy expectations, and investor risk appetite.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial, macroeconomic, or investment advice. Economic data may be revised or priced into markets before release. Market reactions can be unpredictable. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'commodity-fa', title: 'Commodity Fundamental Analysis', level: 'Intermediate', summary: 'Applying fundamental analysis to gold, oil, and other commodities.',
        content: [
          { type: 'image', src: 'images/SNRFA023.jpg', alt: 'Commodity Fundamental Analysis' },
          { type: 'paragraph', text: 'Commodity fundamental analysis evaluates the supply, demand, inventory, production, consumption, and macroeconomic factors that influence commodity prices. Unlike company analysis, commodity analysis focuses on physical market dynamics and global economic conditions.' },
          { type: 'heading', text: 'By Commodity Type' },
          { type: 'paragraph', text: 'For energy commodities such as crude oil and natural gas, analysts study production levels, OPEC+ decisions, inventories, refinery demand, and geopolitical risk. For metals such as gold, silver, and copper, analysis may include interest rates, currency strength, industrial demand, mining supply, and inflation expectations. For agricultural commodities, weather, crop yields, planting cycles, export demand, and government policy are important.' },
          { type: 'heading', text: 'Supply, Demand, and Expectations' },
          { type: 'paragraph', text: 'Supply and demand balance is the core of commodity analysis. If demand rises while supply is constrained, prices may increase. However, commodity prices also move based on expectations — traders often price in future shortages or demand growth before actual data confirms them. Inventories are especially important: low inventories may increase price sensitivity to supply shocks, while high inventories may reduce upside pressure.' },
          { type: 'paragraph', text: 'Professional commodity analysis combines physical market data with macroeconomic trends, futures curve structure, seasonality, geopolitical developments, and technical confirmation.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Commodity fundamental analysis studies real-world supply, demand, inventory, production, consumption, and macroeconomic forces to understand price behavior.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to trade any commodity or financial instrument. Commodity markets can be highly volatile. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'crypto-fa', title: 'Crypto Fundamental Analysis', level: 'Intermediate', summary: 'Evaluating cryptocurrencies beyond price charts.',
        content: [
          { type: 'image', src: 'images/SNRFA024.jpg', alt: 'Crypto Fundamental Analysis' },
          { type: 'paragraph', text: 'Crypto fundamental analysis evaluates the underlying value, utility, adoption, security, token economics, governance, and ecosystem strength of a digital asset. Unlike traditional stock analysis, crypto analysis often does not involve conventional income statements. Instead, it focuses on network fundamentals and project-level sustainability.' },
          { type: 'heading', text: 'Key Areas of Analysis' },
          { type: 'paragraph', text: 'Key areas include blockchain utility, transaction activity, developer activity, ecosystem adoption, token supply, inflation schedule, staking mechanics, fee generation, decentralization, governance, security history, liquidity, exchange listings, and regulatory risk.' },
          { type: 'heading', text: 'Tokenomics' },
          { type: 'paragraph', text: 'Tokenomics is a central part of crypto analysis. Investors must understand total supply, circulating supply, emission schedule, token unlocks, allocation to insiders, staking rewards, burn mechanisms, and demand drivers. A project may have strong technology but poor token economics, which can create price pressure.' },
          { type: 'heading', text: 'Network Activity and Risk' },
          { type: 'paragraph', text: 'A blockchain with increasing users, transactions, developers, applications, and liquidity may indicate stronger adoption. Crypto fundamental analysis also includes risk assessment: smart contract vulnerabilities, bridge hacks, centralized control, weak governance, regulatory pressure, and low liquidity can significantly affect value.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Crypto fundamental analysis evaluates digital assets through network utility, adoption, tokenomics, security, governance, liquidity, and long-term ecosystem viability.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or hold any cryptocurrency or financial instrument. Crypto assets are highly volatile and may involve technology risk, regulatory uncertainty, and possible total loss of capital. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
      { id: 'forex-fa', title: 'Forex Fundamental Analysis', level: 'Intermediate', summary: 'Using macroeconomic data to trade currency pairs.',
        content: [
          { type: 'image', src: 'images/SNRFA025.jpg', alt: 'Forex Fundamental Analysis' },
          { type: 'paragraph', text: 'Forex fundamental analysis evaluates the economic, monetary, and political factors that influence currency values. Since currencies represent national economies, their prices are affected by interest rates, inflation, employment, GDP growth, trade balance, fiscal policy, central bank decisions, capital flows, and geopolitical risk.' },
          { type: 'heading', text: 'Key Drivers' },
          { type: 'paragraph', text: 'Interest rates are one of the strongest drivers of currency value. A currency may strengthen when its central bank raises rates or signals tighter monetary policy, especially if other countries maintain lower rates. However, rate expectations often matter more than the rate decision itself. Employment and GDP data help investors assess economic strength and future policy direction.' },
          { type: 'heading', text: 'Trade Balance and Capital Flows' },
          { type: 'paragraph', text: 'Trade balance and capital flows influence currency demand. Countries with strong exports or significant foreign investment may experience stronger currency demand. Political stability, fiscal discipline, and investor confidence also affect currency valuation.' },
          { type: 'heading', text: 'Analyzing Currency Pairs' },
          { type: 'paragraph', text: 'Professional forex analysis focuses on relative strength. A currency pair compares two economies, not one. For example, EUR/USD depends on both Eurozone and US conditions. Traders must analyze which currency is fundamentally stronger relative to the other. Forex fundamentals should be combined with technical levels, market sentiment, risk appetite, and event timing because currency markets often react sharply to news and central bank communication.' },
          { type: 'callout', text: '<strong>Professional Interpretation:</strong> Forex fundamental analysis evaluates currencies by comparing economic strength, monetary policy, inflation, growth, capital flows, and geopolitical risk between economies.' },
          { type: 'callout', text: '<strong>Disclaimer:</strong> This content is provided strictly for educational and informational purposes only. It does not constitute financial advice or a recommendation to buy, sell, or trade any currency, forex pair, or financial instrument. Forex trading involves significant risk, especially when leverage is used. Currency prices may be affected by central bank policy, economic data, geopolitical events, and market sentiment. Conduct your own research and consult qualified professionals before making financial decisions.' },
        ]
      },
    ]
  },
];
